    // Turbo / Fullscreen / Ambient
    'toggleTurbo', 'togglePaytable', 'toggleAmbientSlot',
    // Stats / Bankroll / Win Goal
    'openStatsPanel', 'closeStatsPanel', 'openBankrollManager',
