// Sprint 178: Volatility indicator (std dev of recent results)
var _volResults178 = [];
function _resetVolatility() {
    _volResults178 = [];
    var el = document.getElementById('volatilityBadge');
    if (el) el.style.display = 'none';
}
function _updateVolatility(winAmount, betAmount) {
    if (!betAmount || betAmount <= 0) return;
    var mult = (winAmount || 0) / betAmount;
    _volResults178.push(mult);
    if (_volResults178.length > 20) _volResults178.shift();
    if (_volResults178.length < 5) return;
    var sum = 0;
    for (var i = 0; i < _volResults178.length; i++) sum += _volResults178[i];
    var mean = sum / _volResults178.length;
    var sqDiffSum = 0;
    for (var j = 0; j < _volResults178.length; j++) {
        var d = _volResults178[j] - mean;
        sqDiffSum += d * d;
    }
    var stdDev = Math.sqrt(sqDiffSum / _volResults178.length);
    var el = document.getElementById('volatilityBadge');
    if (!el) return;
    var label = stdDev >= 3 ? 'HIGH VOL' : stdDev >= 1 ? 'MED VOL' : 'LOW VOL';
    var cls = stdDev >= 3 ? 'vol-high' : stdDev >= 1 ? 'vol-med' : 'vol-low';
    el.textContent = label;
    el.className = 'volatility-badge ' + cls;
    el.style.display = '';
}


