// Sprint 182: Loss recovery percentage (how much of losses recovered)
var _peakBal182 = 0; var _troughBal182 = 0; var _inDrawdown182 = false;
function _resetLossRecovery() {
    _peakBal182 = (typeof balance !== 'undefined') ? balance : 0;
    _troughBal182 = _peakBal182;
    _inDrawdown182 = false;
    var el = document.getElementById('lossRecoveryBadge');
    if (el) el.style.display = 'none';
}
function _updateLossRecovery() {
    var cur = (typeof balance !== 'undefined') ? balance : 0;
    if (cur > _peakBal182) {
        _peakBal182 = cur;
        _troughBal182 = cur;
        _inDrawdown182 = false;
        var el = document.getElementById('lossRecoveryBadge');
        if (el) el.style.display = 'none';
        return;
    }
    if (cur < _troughBal182) {
        _troughBal182 = cur;
        _inDrawdown182 = true;
    }
    if (!_inDrawdown182) return;
    var drawdown = _peakBal182 - _troughBal182;
    if (drawdown <= 0) return;
    var recovered = cur - _troughBal182;
    var pct = Math.min(Math.round((recovered / drawdown) * 100), 100);
    var el = document.getElementById('lossRecoveryBadge');
    if (!el) return;
    if (pct > 0 && pct < 100) {
        el.textContent = pct + '% recovered';
        el.className = 'loss-recovery-badge' + (pct >= 75 ? ' lrb-high' : pct >= 40 ? ' lrb-mid' : ' lrb-low');
        el.style.display = '';
    } else {
        el.style.display = 'none';
    }
}

// Sprint 183: Symbol frequency tracker (most seen symbol this session)
var _symFreq183 = {};
function _resetSymbolFreq() {
    _symFreq183 = {};
    var el = document.getElementById('symbolFreqBadge');
    if (el) el.style.display = 'none';
}
function _updateSymbolFreq(grid) {
    if (!grid || !grid.length) return;
    for (var c = 0; c < grid.length; c++) {
        if (!grid[c]) continue;
        for (var r = 0; r < grid[c].length; r++) {
            var s = grid[c][r];
            if (s) _symFreq183[s] = (_symFreq183[s] || 0) + 1;
        }
    }
    var topSym = null; var topCount = 0;
    var keys = Object.keys(_symFreq183);
    for (var i = 0; i < keys.length; i++) {
        if (_symFreq183[keys[i]] > topCount) { topCount = _symFreq183[keys[i]]; topSym = keys[i]; }
    }
    var el = document.getElementById('symbolFreqBadge');
    if (!el || !topSym) return;
    el.textContent = topSym.slice(0, 8) + ': ' + topCount + 'x';
    el.style.display = '';
}

// Sprint 184: Bankroll health indicator
function _resetBankrollHealth() {
    var el = document.getElementById('bankrollHealthBadge');
    if (el) el.style.display = 'none';
}
function _updateBankrollHealth(betAmount) {
    if (!betAmount || betAmount <= 0) return;
    var bal = (typeof balance !== 'undefined') ? balance : 0;
    if (bal <= 0) return;
    var ratio = bal / betAmount;
    var el = document.getElementById('bankrollHealthBadge');
    if (!el) return;
    var label, cls;
    if (ratio >= 100) { label = 'HEALTHY'; cls = 'brh-healthy'; }
    else if (ratio >= 50) { label = 'STABLE'; cls = 'brh-stable'; }
    else if (ratio >= 20) { label = 'CAUTION'; cls = 'brh-caution'; }
    else if (ratio >= 5) { label = 'DANGER'; cls = 'brh-danger'; }
    else { label = 'CRITICAL'; cls = 'brh-critical'; }
    el.textContent = label + ' (' + Math.floor(ratio) + ' bets left)';
    el.className = 'bankroll-health-badge ' + cls;
    el.style.display = '';
}

// Sprint 185: Risk score (composite of bet size, volatility, streak)
var _riskSpins185 = 0; var _riskBigBets185 = 0; var _riskLosses185 = 0;
function _resetRiskScore() {
    _riskSpins185 = 0; _riskBigBets185 = 0; _riskLosses185 = 0;
    var el = document.getElementById('riskScoreBadge');
    if (el) el.style.display = 'none';
}
function _updateRiskScore(betAmount, won) {
    if (!betAmount || betAmount <= 0) return;
    _riskSpins185++;
    var bal = (typeof balance !== 'undefined') ? balance : 0;
    if (bal > 0 && (betAmount / bal) > 0.05) _riskBigBets185++;
    if (!won) _riskLosses185++;
    if (_riskSpins185 < 5) return;
    // Risk factors: big bet %, loss rate, bet-to-balance ratio
    var bigBetPct = _riskBigBets185 / _riskSpins185;
    var lossRate = _riskLosses185 / _riskSpins185;
    var score = Math.round((bigBetPct * 40 + lossRate * 40 + (bal <= 0 ? 20 : 0)));
    score = Math.min(score, 100);
    var el = document.getElementById('riskScoreBadge');
    if (!el) return;
    var label, cls;
    if (score >= 70) { label = 'HIGH RISK'; cls = 'rs-high'; }
    else if (score >= 40) { label = 'MED RISK'; cls = 'rs-med'; }
    else { label = 'LOW RISK'; cls = 'rs-low'; }
    el.textContent = label + ' ' + score;
    el.className = 'risk-score-badge ' + cls;
    el.style.display = '';
}

// Sprint 186: Quick game rating (thumbs up/down per game, stored in localStorage)
var _gameRatingKey186 = 'casino_game_rating_';
function _resetGameRating() {
    var el = document.getElementById('gameRatingWidget');
    if (!el) return;
    var gid = (typeof currentGame !== 'undefined' && currentGame) ? currentGame.id : null;
    if (!gid) { el.style.display = 'none'; return; }
    var key = _gameRatingKey186 + gid;
    var saved = localStorage.getItem(key);
    _renderGameRating186(el, gid, saved);
    el.style.display = '';
}
function _renderGameRating186(el, gid, rating) {
    var key = _gameRatingKey186 + gid;
    var upCls = rating === 'up' ? ' gr-active' : '';
    var downCls = rating === 'down' ? ' gr-active' : '';
    el.innerHTML = '<span class="gr-label">Rate:</span>' +
        '<button class="gr-btn gr-up' + upCls + '" data-rating="up" data-gid="' + gid + '">\u{1F44D}</button>' +
        '<button class="gr-btn gr-down' + downCls + '" data-rating="down" data-gid="' + gid + '">\u{1F44E}</button>';
    el.querySelectorAll('.gr-btn').forEach(function(btn) {
        btn.onclick = function() {
            var r = btn.getAttribute('data-rating');
            var g = btn.getAttribute('data-gid');
            var k = _gameRatingKey186 + g;
            var prev = localStorage.getItem(k);
            if (prev === r) {
                localStorage.removeItem(k);
                _renderGameRating186(el, g, null);
            } else {
                try { localStorage.setItem(k, r); } catch(e) {}
                _renderGameRating186(el, g, r);
            }
        };
    });
}


