// Sprint 200: Balance trajectory (are we trending up, down, or flat?)
var _trajHistory200 = [];
function _resetBalanceTrajectory() {
    _trajHistory200 = [];
    var el = document.getElementById('balanceTrajBadge');
    if (el) el.style.display = 'none';
}
function _updateBalanceTrajectory() {
    var cur = (typeof balance !== 'undefined') ? balance : 0;
    _trajHistory200.push(cur);
    if (_trajHistory200.length > 10) _trajHistory200.shift();
    if (_trajHistory200.length < 5) return;
    var el = document.getElementById('balanceTrajBadge');
    if (!el) return;
    // Simple linear regression slope
    var n = _trajHistory200.length;
    var sumX = 0; var sumY = 0; var sumXY = 0; var sumXX = 0;
    for (var i = 0; i < n; i++) {
        sumX += i; sumY += _trajHistory200[i];
        sumXY += i * _trajHistory200[i]; sumXX += i * i;
    }
    var slope = (n * sumXY - sumX * sumY) / (n * sumXX - sumX * sumX);
    var arrow, cls;
    if (slope > 5) { arrow = '\u2197'; cls = 'bt-up'; }       // ↗
    else if (slope > 0.5) { arrow = '\u2192'; cls = 'bt-flat'; } // →
    else if (slope > -5) { arrow = '\u2192'; cls = 'bt-flat'; }  // →
    else { arrow = '\u2198'; cls = 'bt-down'; }                 // ↘
    el.textContent = arrow + ' Trend';
    el.className = 'balance-traj-badge ' + cls;
    el.style.display = '';
}

