// Sprint 219: Push session data to server insights API
function _pushSessionInsights219(winAmount, betAmount) {
    // Silently push session summary every 25 spins
    if (typeof _sessionSummary207 === 'undefined' || !_sessionSummary207) return;
    if (!_sessionSummary207.spins || _sessionSummary207.spins % 25 !== 0) return;
    var userId = 'anon';
    try {
        var userStr = localStorage.getItem('casinoUser');
        if (userStr) { var u = JSON.parse(userStr); userId = u.id || u.username || 'anon'; }
    } catch(e) {}
    var data = {
        userId: String(userId),
        gameId: _sessionSummary207.gameId || 'unknown',
        spins: _sessionSummary207.spins,
        wins: _sessionSummary207.wins,
        totalWagered: _sessionSummary207.totalWagered,
        totalWon: _sessionSummary207.totalWon,
        biggestWin: _sessionSummary207.biggestWin,
        duration: Math.round((Date.now() - (_sessionSummary207.startTime || Date.now())) / 1000)
    };
    fetch('/api/session-insights/log', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data)
    }).catch(function() {}); // fire-and-forget
}

// Sprint 220: Momentum meter (rolling 5-spin net trend)
var _momentum220 = [];
function _resetMomentum() {
    _momentum220 = [];
    var el = document.getElementById('momentumMeter');
    if (el) el.style.display = 'none';
}
function _updateMomentum(winAmount, betAmount) {
    if (!betAmount || betAmount <= 0) return;
    var net = (winAmount || 0) - betAmount;
    _momentum220.push(net);
    if (_momentum220.length > 5) _momentum220.shift();
    if (_momentum220.length < 3) return;
    var sum = 0;
    for (var i = 0; i < _momentum220.length; i++) sum += _momentum220[i];
    var el = document.getElementById('momentumMeter');
    if (!el) return;
    var arrow, cls;
    if (sum > betAmount * 2) { arrow = '\u{1F680}'; cls = 'mm-rocket'; }
    else if (sum > 0) { arrow = '\u2197'; cls = 'mm-up'; }
    else if (sum > -betAmount * 2) { arrow = '\u2192'; cls = 'mm-flat'; }
    else { arrow = '\u2198'; cls = 'mm-down'; }
    el.textContent = arrow + ' Momentum';
    el.className = 'momentum-meter ' + cls;
    el.style.display = '';
}

// Sprint 221: Payline coverage indicator (shows active paylines)
function _resetPaylineCoverage() {
    var el = document.getElementById('paylineBadge');
    if (!el) return;
    if (typeof currentGame === 'undefined' || !currentGame) { el.style.display = 'none'; return; }
    var lines = currentGame.paylines || currentGame.lines || 0;
    if (lines > 0) {
        el.textContent = lines + ' payline' + (lines > 1 ? 's' : '');
        el.style.display = '';
    } else {
        el.style.display = 'none';
    }
}

// Sprint 222: Bet ladder position (where current bet ranks among BET_STEPS)
function _resetBetLadder() {
    _updateBetLadder222();
}
function _updateBetLadder222() {
    var el = document.getElementById('betLadderBadge');
    if (!el) return;
    if (typeof BET_STEPS === 'undefined' || typeof currentBet === 'undefined') { el.style.display = 'none'; return; }
    var pos = 0;
    for (var i = 0; i < BET_STEPS.length; i++) {
        if (currentBet >= BET_STEPS[i]) pos = i + 1;
    }
    var total = BET_STEPS.length;
    var pct = Math.round((pos / total) * 100);
    el.textContent = 'Bet ' + pos + '/' + total + ' (' + pct + '%)';
    el.className = 'bet-ladder-badge' + (pct >= 75 ? ' blb-high' : pct >= 25 ? ' blb-mid' : ' blb-low');
    el.style.display = '';
}

// Sprint 223: Cold game alert (warns if RTP is significantly below expected)
var _coldWag223 = 0; var _coldWon223 = 0;
function _resetColdGameAlert() {
    _coldWag223 = 0; _coldWon223 = 0;
    var el = document.getElementById('coldGameAlert');
    if (el) el.style.display = 'none';
}
function _updateColdGameAlert(winAmount, betAmount) {
    if (!betAmount || betAmount <= 0) return;
    _coldWag223 += betAmount;
    _coldWon223 += (winAmount || 0);
    if (_coldWag223 < 50) return; // need at least $50 wagered for meaningful data
    var rtp = (_coldWon223 / _coldWag223) * 100;
    var el = document.getElementById('coldGameAlert');
    if (!el) return;
    if (rtp < 70) {
        el.textContent = '\u{1F9CA} Cold game! RTP ' + rtp.toFixed(0) + '%';
        el.className = 'cold-game-alert cga-cold';
        el.style.display = '';
    } else if (rtp < 80) {
        el.textContent = 'Below avg RTP ' + rtp.toFixed(0) + '%';
        el.className = 'cold-game-alert cga-cool';
        el.style.display = '';
    } else {
        el.style.display = 'none';
    }
}

// Sprint 224: Win size distribution (small/medium/big/mega percentages)
var _winDist224 = { small: 0, medium: 0, big: 0, mega: 0, total: 0 };
function _resetWinDistribution() {
    _winDist224 = { small: 0, medium: 0, big: 0, mega: 0, total: 0 };
    var el = document.getElementById('winDistBadge');
    if (el) el.style.display = 'none';
}
function _updateWinDistribution(winAmount, betAmount) {
    if (!winAmount || winAmount <= 0 || !betAmount || betAmount <= 0) return;
    var mult = winAmount / betAmount;
    _winDist224.total++;
    if (mult >= 20) _winDist224.mega++;
    else if (mult >= 5) _winDist224.big++;
    else if (mult >= 2) _winDist224.medium++;
    else _winDist224.small++;
    if (_winDist224.total < 3) return;
    var el = document.getElementById('winDistBadge');
    if (!el) return;
    var t = _winDist224.total;
    var parts = [];
    if (_winDist224.mega > 0) parts.push(Math.round(_winDist224.mega / t * 100) + '% mega');
    if (_winDist224.big > 0) parts.push(Math.round(_winDist224.big / t * 100) + '% big');
    parts.push(Math.round(_winDist224.medium / t * 100) + '% med');
    el.textContent = parts.join(' ');
    el.style.display = '';
}

// Sprint 225: Total session ROI badge (clear profit/loss percentage)
