// Sprint 236 — Responsible gambling timer
var _rgTimer236 = { startTime: 0, limitMinutes: 60, warned: false, hardLimit: 120 };
function _resetRGTimer() {
    _rgTimer236.startTime = Date.now();
    _rgTimer236.warned = false;
    var el = document.getElementById('rgTimerBadge');
    if (el) el.style.display = 'none';
}
function _updateRGTimer() {
    var el = document.getElementById('rgTimerBadge');
    if (!el) return;
    var elapsed = (Date.now() - _rgTimer236.startTime) / 60000;
    if (elapsed >= _rgTimer236.hardLimit) {
        el.textContent = 'Session limit reached (' + Math.floor(elapsed) + 'min)';
        el.className = 'rg-timer-badge rgt-critical';
        el.style.display = '';
        // Show mandatory break popup
        _showRGPopup('You have been playing for ' + Math.floor(elapsed) + ' minutes. Please take a break for your wellbeing.');
    } else if (elapsed >= _rgTimer236.limitMinutes && !_rgTimer236.warned) {
        _rgTimer236.warned = true;
        el.textContent = 'Playing ' + Math.floor(elapsed) + 'min — consider a break';
        el.className = 'rg-timer-badge rgt-warn';
        el.style.display = '';
        _showRGPopup('You have been playing for ' + Math.floor(elapsed) + ' minutes. Would you like to take a break?');
    } else if (elapsed >= 30) {
        el.textContent = 'Session: ' + Math.floor(elapsed) + 'min';
        el.className = 'rg-timer-badge rgt-info';
        el.style.display = '';
    }
}
function _showRGPopup(message) {
    var overlay = document.getElementById('rgOverlay');
    if (!overlay) return;
    var msgEl = document.getElementById('rgPopupMessage');
    if (msgEl) msgEl.textContent = message;
    overlay.style.display = 'flex';
}
function _closeRGPopup() {
    var overlay = document.getElementById('rgOverlay');
    if (overlay) overlay.style.display = 'none';
}

// Sprint 237 — Loss limit alert
var _lossLimit237 = { limit: 500, totalLost: 0, warned: false };
