// Sprint 240 — Bet history export (CSV download)
var _betHistory240 = [];
function _resetBetHistoryExport() {
    _betHistory240 = [];
}
function _logBetForExport(winAmount, betAmount) {
    var game = (typeof currentGame !== 'undefined') ? currentGame : 'unknown';
    _betHistory240.push({
        time: new Date().toISOString(),
        game: game,
        bet: betAmount || 0,
        win: winAmount || 0,
        net: (winAmount || 0) - (betAmount || 0),
        balance: (typeof balance !== 'undefined') ? balance : 0
    });
}
function _exportBetHistory() {
    if (_betHistory240.length === 0) { alert('No spin history to export yet.'); return; }
    var csv = 'Time,Game,Bet,Win,Net,Balance\n';
    _betHistory240.forEach(function(row) {
        csv += row.time + ',' + row.game + ',' + row.bet + ',' + row.win + ',' + row.net + ',' + row.balance + '\n';
    });
    var blob = new Blob([csv], { type: 'text/csv' });
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url;
    a.download = 'matrix_spins_history_' + new Date().toISOString().slice(0, 10) + '.csv';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
}

// Sprint 241 — Provably fair hash display
var _fairHash241 = { serverSeed: '', clientSeed: '', nonce: 0, lastHash: '' };
function _resetProvablyFair() {
    _fairHash241.serverSeed = _generateSeed();
    _fairHash241.clientSeed = _generateSeed();
    _fairHash241.nonce = 0;
    _fairHash241.lastHash = '';
    var el = document.getElementById('fairHashBadge');
    if (el) el.style.display = 'none';
}
function _generateSeed() {
    var chars = 'abcdef0123456789';
    var s = '';
    for (var i = 0; i < 32; i++) s += chars[Math.floor(Math.random() * chars.length)];
    return s;
}
function _updateProvablyFair() {
    _fairHash241.nonce++;
    var input = _fairHash241.serverSeed + ':' + _fairHash241.clientSeed + ':' + _fairHash241.nonce;
    // Simple hash for display (real implementation would use crypto.subtle)
    var hash = 0;
    for (var i = 0; i < input.length; i++) {
        var chr = input.charCodeAt(i);
        hash = ((hash << 5) - hash) + chr;
        hash |= 0;
    }
    _fairHash241.lastHash = Math.abs(hash).toString(16).padStart(8, '0');
    var el = document.getElementById('fairHashBadge');
    if (!el) return;
    el.textContent = 'Fair: #' + _fairHash241.lastHash;
    el.title = 'Nonce: ' + _fairHash241.nonce + ' | Server Seed Hash: ' + _fairHash241.serverSeed.slice(0, 8) + '...';
    el.className = 'fair-hash-badge';
    el.style.display = '';
}

// Sprint 242 — Self-exclusion option
var _selfExclusion242 = { active: false, until: 0 };
function _resetSelfExclusion() {
    // Check if exclusion is active
    try {
        var raw = localStorage.getItem('matrixSpins_selfExclusion');
        if (raw) {
            var data = JSON.parse(raw);
            if (data.until > Date.now()) {
                _selfExclusion242.active = true;
                _selfExclusion242.until = data.until;
                _showSelfExclusionScreen();
                return;
            }
        }
    } catch(e) {}
    _selfExclusion242.active = false;
}
function _activateSelfExclusion(hours) {
    var h = hours || 24;
    _selfExclusion242.active = true;
    _selfExclusion242.until = Date.now() + (h * 3600000);
    try { localStorage.setItem('matrixSpins_selfExclusion', JSON.stringify({ until: _selfExclusion242.until })); } catch(e) {}
    _showSelfExclusionScreen();
}
function _showSelfExclusionScreen() {
    var overlay = document.getElementById('selfExclusionOverlay');
    if (!overlay) return;
    var remaining = Math.max(0, _selfExclusion242.until - Date.now());
    var hours = Math.floor(remaining / 3600000);
    var mins = Math.floor((remaining % 3600000) / 60000);
    var msgEl = document.getElementById('selfExclusionMessage');
    if (msgEl) msgEl.textContent = 'Self-exclusion active. You can return in ' + hours + 'h ' + mins + 'm. Take care of yourself.';
    overlay.style.display = 'flex';
}
function _cancelSelfExclusion() {
    _selfExclusion242.active = false;
    try { localStorage.removeItem('matrixSpins_selfExclusion'); } catch(e) {}
    var overlay = document.getElementById('selfExclusionOverlay');
    if (overlay) overlay.style.display = 'none';
}


