// Sprint 249 — Anti-fraud spin validation
var _antifraud249 = { lastOutcomes: [], expectedRange: { min: 85, max: 115 } };
function _resetAntifraud() {
    _antifraud249.lastOutcomes = [];
}
function _validateSpin(winAmount, betAmount) {
    if (!betAmount || betAmount <= 0) return true;
    var ratio = (winAmount || 0) / betAmount;
    _antifraud249.lastOutcomes.push(ratio);
    if (_antifraud249.lastOutcomes.length > 100) _antifraud249.lastOutcomes.shift();
    // Check for statistical anomalies (client-side sanity check)
    if (_antifraud249.lastOutcomes.length >= 20) {
        var sum = 0;
        _antifraud249.lastOutcomes.forEach(function(r) { sum += r; });
        var avg = (sum / _antifraud249.lastOutcomes.length) * 100;
        // Flag if average payout deviates significantly from expected RTP
        if (avg > 130 || avg < 60) {
            console.warn('[AntifraudClient] Unusual payout pattern detected: avg=' + avg.toFixed(1) + '%');
        }
    }
    return true;
}

