function _installPWA() {
    if (!_deferredPrompt261) return;
    _deferredPrompt261.prompt();
    _deferredPrompt261.userChoice.then(function(choice) {
        _deferredPrompt261 = null;
        var btn = document.getElementById('pwaInstallBtn');
        if (btn) btn.style.display = 'none';
    });
}

// Sprint 262 — Offline mode detection
function _initOfflineDetection() {
    function updateOnlineStatus() {
        var el = document.getElementById('offlineBadge');
        if (!el) return;
        if (navigator.onLine) {
            el.style.display = 'none';
        } else {
            el.textContent = 'OFFLINE - Reconnect to continue';
            el.className = 'offline-badge';
            el.style.display = '';
        }
    }
    window.addEventListener('online', updateOnlineStatus);
    window.addEventListener('offline', updateOnlineStatus);
    updateOnlineStatus();
}

// Sprint 263 — Lazy loading for game assets
function _initLazyLoading() {
    if ('IntersectionObserver' in window) {
        var observer = new IntersectionObserver(function(entries) {
            entries.forEach(function(entry) {
                if (entry.isIntersecting) {
                    var img = entry.target;
                    if (img.dataset.src) {
                        img.src = img.dataset.src;
                        img.removeAttribute('data-src');
                        observer.unobserve(img);
                    }
                }
            });
        }, { rootMargin: '100px' });
        document.querySelectorAll('img[data-src]').forEach(function(img) {
            observer.observe(img);
        });
    }
}

// Sprint 264 — Preload animation
function _showPreloader() {
    var el = document.getElementById('preloaderOverlay');
    if (el) el.style.display = 'flex';
}
function _hidePreloader() {
    var el = document.getElementById('preloaderOverlay');
    if (el) {
        el.style.opacity = '0';
        setTimeout(function() { el.style.display = 'none'; el.style.opacity = '1'; }, 500);
    }
}

// Sprint 265 — Low battery warning
function _initBatteryWarning() {
    if (!navigator.getBattery) return;
    navigator.getBattery().then(function(battery) {
        function checkBattery() {
            var el = document.getElementById('batteryBadge');
            if (!el) return;
            if (!battery.charging && battery.level <= 0.15) {
                el.textContent = 'Low Battery: ' + Math.round(battery.level * 100) + '%';
                el.className = 'battery-badge bat-low';
                el.style.display = '';
            } else if (!battery.charging && battery.level <= 0.30) {
                el.textContent = 'Battery: ' + Math.round(battery.level * 100) + '%';
                el.className = 'battery-badge bat-mid';
                el.style.display = '';
            } else {
                el.style.display = 'none';
            }
        }
        battery.addEventListener('levelchange', checkBattery);
        battery.addEventListener('chargingchange', checkBattery);
        checkBattery();
    });
}

// Sprint 266 — Haptic feedback on win
function _hapticWin(multiplier) {
    if (!navigator.vibrate) return;
    if (multiplier >= 10) {
        navigator.vibrate([100, 50, 100, 50, 200]); // Big win pattern
    } else if (multiplier >= 2) {
        navigator.vibrate([80, 40, 80]); // Medium win
    } else if (multiplier > 0) {
        navigator.vibrate(50); // Small win
    }
}


