function _initCryptoWallet() {
    // Generate display addresses
    var chars = '0123456789abcdef';
    function genAddr(prefix, len) {
        var s = prefix;
        for (var i = 0; i < len; i++) s += chars[Math.floor(Math.random() * chars.length)];
        return s;
    }
    _crypto268.wallets.BTC.address = genAddr('bc1q', 38);
    _crypto268.wallets.ETH.address = genAddr('0x', 40);
    _crypto268.wallets.USDT.address = genAddr('T', 33);
}
