// Sprint 269 — Wagering requirements tracker
var _wagering269 = { required: 0, wagered: 0, remaining: 0, multiplier: 35 };
function _resetWagering() {
    var el = document.getElementById('wageringBadge');
    if (el) el.style.display = (_wagering269.remaining > 0) ? '' : 'none';
    _updateWageringBadge();
}
function _addBonusWagering(bonusAmount) {
    _wagering269.required = bonusAmount * _wagering269.multiplier;
    _wagering269.wagered = 0;
    _wagering269.remaining = _wagering269.required;
    _updateWageringBadge();
}
function _updateWagering(betAmount) {
    if (_wagering269.remaining <= 0) return;
    _wagering269.wagered += (betAmount || 0);
    _wagering269.remaining = Math.max(0, _wagering269.required - _wagering269.wagered);
    _updateWageringBadge();
}
function _updateWageringBadge() {
    var el = document.getElementById('wageringBadge');
    if (!el) return;
    if (_wagering269.remaining <= 0) { el.style.display = 'none'; return; }
    var pct = Math.min(100, (_wagering269.wagered / _wagering269.required) * 100);
    el.textContent = 'Wagering: ' + pct.toFixed(0) + '% ($' + Math.floor(_wagering269.remaining) + ' left)';
    el.className = 'wagering-badge' + (pct >= 75 ? ' wg-almost' : ' wg-active');
    el.style.display = '';
}

// Sprint 270 — Cashback rewards
var _cashback270 = { rate: 0.05, losses: 0, lastPaid: 0, accumulated: 0 };
function _resetCashback() {
    try {
        var raw = localStorage.getItem('matrixSpins_cashback');
        if (raw) {
            var data = JSON.parse(raw);
            _cashback270.accumulated = data.accumulated || 0;
            _cashback270.losses = data.losses || 0;
        }
    } catch(e) {}
    _updateCashbackBadge();
}
function _updateCashback(winAmount, betAmount) {
    if (!betAmount || betAmount <= 0) return;
    var net = (winAmount || 0) - betAmount;
    if (net < 0) {
        _cashback270.losses += Math.abs(net);
        _cashback270.accumulated = _cashback270.losses * _cashback270.rate;
    }
    try { localStorage.setItem('matrixSpins_cashback', JSON.stringify(_cashback270)); } catch(e) {}
    _updateCashbackBadge();
}
function _updateCashbackBadge() {
    var el = document.getElementById('cashbackBadge');
    if (!el) return;
    if (_cashback270.accumulated < 1) { el.style.display = 'none'; return; }
    el.textContent = 'Cashback: $' + _cashback270.accumulated.toFixed(2);
    el.className = 'cashback-badge';
    el.style.display = '';
}
function _claimCashback() {
    if (_cashback270.accumulated < 5) { alert('Minimum cashback claim is $5'); return; }
    var amount = Math.floor(_cashback270.accumulated);
    if (typeof balance !== 'undefined') balance += amount;
    var betDisplay = document.getElementById('balanceAmount');
    if (betDisplay) betDisplay.textContent = balance;
    _cashback270.accumulated = 0;
    _cashback270.losses = 0;
    try { localStorage.setItem('matrixSpins_cashback', JSON.stringify(_cashback270)); } catch(e) {}
    _updateCashbackBadge();
    alert('$' + amount + ' cashback credited to your balance!');
}

