    html += '<div class="kyc-step' + (_kyc275.level >= 3 ? ' ks-done' : '') + '"><span class="ks-num">3</span><span class="ks-label">Address Verification</span>' + (_kyc275.level >= 3 ? '<span class="ks-check">\u2713</span>' : '<span class="ks-lock">\u{1F512}</span>') + '</div>';
