    if (_kyc275.level < 3) html += '<p>Complete verification to unlock unlimited withdrawals and VIP perks.</p>';
    else html += '<p class="kyc-verified-msg">\u2705 Your account is fully verified. Enjoy unlimited withdrawals!</p>';
    html += '</div>';
