// Advanced Game Mechanics & Retention

// Sprint 283 — Bonus buy feature
var _bonusBuy283 = { cost: 0, multiplier: 80 }; // Cost = bet * multiplier
function _getBonusBuyCost() {
    var bet = (typeof currentBet !== 'undefined') ? currentBet : 1;
    return bet * _bonusBuy283.multiplier;
}
function _buyBonus() {
    var cost = _getBonusBuyCost();
    if (typeof balance !== 'undefined' && balance < cost) {
        alert('Insufficient balance. Bonus buy costs $' + cost.toLocaleString());
        return;
    }
    if (!confirm('Buy bonus round for $' + cost.toLocaleString() + '?\n\nThis guarantees entry to the free spins bonus.')) return;
    if (typeof balance !== 'undefined') balance -= cost;
    var betDisplay = document.getElementById('balanceAmount');
    if (betDisplay) betDisplay.textContent = balance;
    // Trigger free spins
    if (typeof freeSpinsActive !== 'undefined') freeSpinsActive = true;
    if (typeof freeSpinsRemaining !== 'undefined') freeSpinsRemaining = 10;
    _logAuditEvent('bonus_buy', { cost: cost });
    var el = document.getElementById('bonusBuyBadge');
    if (el) { el.textContent = 'BONUS ACTIVE!'; el.className = 'bonus-buy-badge bb-active'; el.style.display = ''; }
}
function _updateBonusBuyBadge() {
    var el = document.getElementById('bonusBuyBadge');
    if (!el) return;
    var cost = _getBonusBuyCost();
    el.textContent = 'Buy Bonus: $' + cost.toLocaleString();
    el.className = 'bonus-buy-badge bb-available';
    el.style.display = '';
}

// Sprint 284 — Gamble/double-up mini-game
var _gamble284 = { active: false, amount: 0, history: [] };
function _offerGamble(winAmount) {
    if (!winAmount || winAmount <= 0) return;
    _gamble284.amount = winAmount;
    var el = document.getElementById('gambleOffer');
    if (!el) return;
    el.innerHTML = '<p>You won $' + winAmount.toLocaleString() + '!</p><p>Gamble to double it?</p><div class="gamble-btns"><button class="gamble-btn gb-red" onclick="_gambleChoice(\&quot;red\&quot;)">Red (2x)</button><button class="gamble-btn gb-black" onclick="_gambleChoice(\'black\')">Black (2x)</button><button class="gamble-btn gb-collect" onclick="_gambleCollect()">Collect</button></div>';
    el.style.display = '';
}
function _gambleChoice(color) {
    var win = Math.random() < 0.48; // Slight house edge (48% instead of 50%)
    if (win) {
        _gamble284.amount *= 2;
        _gamble284.history.push({ result: 'win', color: color, amount: _gamble284.amount });
        _offerGamble(_gamble284.amount);
    } else {
        _gamble284.history.push({ result: 'loss', color: color, amount: 0 });
        if (typeof balance !== 'undefined') balance -= _gamble284.amount;
        var betDisplay = document.getElementById('balanceAmount');
        if (betDisplay) betDisplay.textContent = Math.max(0, balance);
        var el = document.getElementById('gambleOffer');
        if (el) { el.innerHTML = '<p class="gamble-loss">You lost $' + _gamble284.amount.toLocaleString() + '!</p>'; setTimeout(function() { el.style.display = 'none'; }, 2000); }
        _gamble284.amount = 0;
    }
}
function _gambleCollect() {
    var el = document.getElementById('gambleOffer');
    if (el) el.style.display = 'none';
    _gamble284.amount = 0;
}

