function _openDepositLimits() {
    var current = localStorage.getItem('ms_deposit_limit') || 'none';
    var limit = prompt('Set your daily deposit limit (USD). Current: ' + current + '\nEnter amount or "none" to remove:');
    if (limit !== null) {
        if (limit === 'none' || limit === '') {
            localStorage.removeItem('ms_deposit_limit');
            alert('Deposit limit removed.');
        } else {
            var val = parseFloat(limit);
            if (!isNaN(val) && val > 0) {
                localStorage.setItem('ms_deposit_limit', val.toString());
                alert('Daily deposit limit set to $' + val.toFixed(2));
            }
        }
    }
}


// Sprint 339 — Stripe Checkout Integration UI
function _openStripeDeposit(amount) {
    var el = document.getElementById('stripeCheckout339');
    if (!el) return;
    el.querySelector('.sc339-amount').textContent = '$' + amount.toFixed(2);
    el.style.display = 'flex';
    fetch('/api/payment/create-checkout', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + (typeof authToken !== 'undefined' ? authToken : '') },
        body: JSON.stringify({ amount: amount })
    }).then(function(r) { return r.json(); }).then(function(data) {
        if (data.url) window.location.href = data.url;
        else if (data.clientSecret) { el.querySelector('.sc339-status').textContent = 'Processing...'; }
        else { el.querySelector('.sc339-status').textContent = data.error || 'Payment setup failed'; }
    }).catch(function() { el.querySelector('.sc339-status').textContent = 'Connection error'; });
}
function _closeStripeCheckout() { var el = document.getElementById('stripeCheckout339'); if (el) el.style.display = 'none'; }


// Sprint 340 — Withdrawal Request Queue UI
function _showWithdrawalQueue() {
    var el = document.getElementById('withdrawalQueue340');
    if (!el) return;
    el.style.display = 'flex';
    el.querySelector('.wq340-list').innerHTML = '<div class="wq340-loading">Loading...</div>';
    fetch('/api/payment/withdrawals', {
        headers: { 'Authorization': 'Bearer ' + (typeof authToken !== 'undefined' ? authToken : '') }
    }).then(function(r) { return r.json(); }).then(function(data) {
        var list = el.querySelector('.wq340-list');
        if (!data.withdrawals || !data.withdrawals.length) { list.innerHTML = '<div class="wq340-empty">No pending withdrawals</div>'; return; }
        list.innerHTML = data.withdrawals.map(function(w) {
            var statusCls = w.status === 'approved' ? 'wq340-approved' : w.status === 'pending' ? 'wq340-pending' : 'wq340-rejected';
            return '<div class="wq340-item"><span>$' + w.amount.toFixed(2) + '</span><span class="' + statusCls + '">' + w.status + '</span><span class="wq340-date">' + new Date(w.created_at).toLocaleDateString() + '</span></div>';
        }).join('');
    }).catch(function() { el.querySelector('.wq340-list').innerHTML = '<div class="wq340-empty">Failed to load</div>'; });
}
function _closeWithdrawalQueue() { var el = document.getElementById('withdrawalQueue340'); if (el) el.style.display = 'none'; }


// Sprint 341 — Transaction History View
function _showTransactionHistory() {
    var el = document.getElementById('txHistory341');
    if (!el) return;
    el.style.display = 'flex';
    fetch('/api/game-history/recent?limit=50', {
        headers: { 'Authorization': 'Bearer ' + (typeof authToken !== 'undefined' ? authToken : '') }
    }).then(function(r) { return r.json(); }).then(function(data) {
        var list = el.querySelector('.tx341-list');
        if (!data.history || !data.history.length) { list.innerHTML = '<div class="tx341-empty">No transactions yet</div>'; return; }
        list.innerHTML = data.history.map(function(t) {
            var cls = t.win_amount > 0 ? 'tx341-win' : 'tx341-loss';
            return '<div class="tx341-item ' + cls + '"><span>' + (t.game_id || 'Spin') + '</span><span>Bet: $' + t.bet_amount.toFixed(2) + '</span><span>' + (t.win_amount > 0 ? '+$' + t.win_amount.toFixed(2) : '-$' + t.bet_amount.toFixed(2)) + '</span></div>';
        }).join('');
    }).catch(function() {});
}
function _closeTxHistory() { var el = document.getElementById('txHistory341'); if (el) el.style.display = 'none'; }


// Sprint 342 — Tax Document Generator
function _generateTaxDoc() {
    var w = (typeof totalWagered !== 'undefined') ? totalWagered : 0;
    var won = (typeof totalWon !== 'undefined') ? totalWon : 0;
    var net = won - w;
    var doc = 'MATRIX SPINS - Annual Tax Summary\n';
    doc += 'Tax Year: ' + new Date().getFullYear() + '\n';
    doc += 'Generated: ' + new Date().toISOString().split('T')[0] + '\n';
    doc += '========================================\n';
    doc += 'Total Amount Wagered: $' + w.toFixed(2) + '\n';
    doc += 'Total Winnings: $' + won.toFixed(2) + '\n';
    doc += 'Net Gambling Income: $' + net.toFixed(2) + '\n';
    doc += '========================================\n';
    doc += 'This document is provided for tax reporting purposes.\n';
    doc += 'Consult a tax professional for your specific situation.\n';
    doc += 'Operator: Matrix Spins (msaart.online)\n';
    var blob = new Blob([doc], {type: 'text/plain'});
    var a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = 'matrix-spins-tax-' + new Date().getFullYear() + '.txt';
    a.click();
}


/* â”€â”€ 339-346 â€” geo-ip country detection â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */
_geoCountry = 'US';
function _initGeoDetection() {
    fetch('https://ipapi.co/json/')
        .then(function(r) { return r.json(); })
        .then(function(d) {
            if (d && d.country_code) {
                _geoCountry = d.country_code;
                console.log('[Geo] Detected country:', _geoCountry);
                var flag = document.getElementById('geoFlag');
                if (flag) flag.textContent = _countryFlag(_geoCountry);
                _checkGeoRestrictions(_geoCountry);
            }
        })
        .catch(function(e) { console.warn('[Geo] Detection failed:', e); });
}
function _countryFlag(cc) {
    var base = 127397;
    return String.fromCodePoint(cc.charCodeAt(0) + base, cc.charCodeAt(1) + base);
}
function _checkGeoRestrictions(cc) {
    var restricted = ['US','AU','GB','FR','IT','ES','TR','SG','HK'];
    var el = document.getElementById('geoRestrictionBanner');
    if (!el) return;
    if (restricted.indexOf(cc) !== -1) {
        el.style.display = 'block';
        el.innerHTML = '<span style="color:#f0ad4e;">&#9888;</span> Gambling regulations may apply in your region (' + cc + '). Please verify local laws before playing.';
    }
}


