        '<div class="referral-code-box"><span>' + _referralCode + '</span><button onclick="_copyReferral()" class="ref-copy-btn">Copy Link</button></div>' +
        '<div class="referral-stats"><span>Referrals: <strong>' + (JSON.parse(localStorage.getItem('ms_referral_count') || '0')) + '</strong></span></div>' +
        '<button onclick="this.parentElement.parentElement.style.display=\&quot;none\&quot;" class="ref-close-btn">&times;</button></div>';
