/* ── 347-354 — push notification opt-in ───────────────────────── */
function _initPushNotifications() {
    if (!('Notification' in window)) return;
    if (Notification.permission === 'granted') return;
    if (localStorage.getItem('ms_push_dismissed') === 'true') return;
    setTimeout(function() {
        var banner = document.createElement('div');
        banner.id = 'pushOptIn354';
        banner.className = 'push-optin-banner';
        banner.innerHTML = '<div class="push-optin-inner">' +
            '<span class="push-icon">\u{1F514}</span>' +
            '<div><strong>Stay Updated!</strong><br><small>Get notified about jackpots, bonuses, and free spins.</small></div>' +
            '<div class="push-btns">' +
            '<button onclick="_enablePush()" class="push-allow-btn">Enable</button>' +
            '<button onclick="_dismissPush()" class="push-dismiss-btn">Not Now</button>' +
            '</div></div>';
        document.body.appendChild(banner);
    }, 30000);
}
function _enablePush() {
    Notification.requestPermission().then(function(perm) {
        if (perm === 'granted') {
            new Notification('Matrix Spins', { body: 'Notifications enabled! You\'ll be the first to know about bonuses.', icon: '/favicon.ico' });
        }
    });
    var el = document.getElementById('pushOptIn354');
    if (el) el.remove();
}
function _dismissPush() {
    localStorage.setItem('ms_push_dismissed', 'true');
    var el = document.getElementById('pushOptIn354');
    if (el) el.remove();
}


/* ── 355-362 — admin player search ────────────────────────────── */
function _adminSearchPlayer() {
    var query = prompt('Enter player ID or email:');
    if (!query) return;
    fetch('/api/admin/players/search?q=' + encodeURIComponent(query), {
        headers: { 'Authorization': 'Bearer ' + (typeof authToken !== 'undefined' ? authToken : '') }
    })
    .then(function(r) { return r.json(); })
    .then(function(data) {
        if (data.players && data.players.length > 0) {
            var p = data.players[0];
            alert('Player: ' + (p.email || p.id) + '\nBalance: $' + (p.balance || 0).toFixed(2) + '\nTotal Wagered: $' + (p.totalWagered || 0).toFixed(2) + '\nJoined: ' + (p.createdAt || 'N/A'));
        } else {
            alert('No player found for: ' + query);
        }
    })
    .catch(function(e) { alert('Search error: ' + e.message); });
}


/* ── 355-362 — admin broadcast message ────────────────────────── */
function _adminBroadcast() {
    var msg = prompt('Enter broadcast message for all players:');
    if (!msg) return;
    var type = prompt('Message type (info/warning/promo):', 'info') || 'info';
    fetch('/api/admin/broadcast', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + (typeof authToken !== 'undefined' ? authToken : '') },
        body: JSON.stringify({ message: msg, type: type })
    })
    .then(function(r) { return r.json(); })
    .then(function(d) { alert('Broadcast sent to ' + (d.recipients || 0) + ' players.'); })
    .catch(function(e) { alert('Broadcast error: ' + e.message); });
    _showBroadcastBanner(msg, type);
}
function _showBroadcastBanner(msg, type) {
    var colors = { info: '#3498db', warning: '#f39c12', promo: '#9b59b6' };
    var banner = document.createElement('div');
    banner.className = 'broadcast-banner';
    banner.style.borderColor = colors[type] || colors.info;
    banner.innerHTML = '<span class="bc-icon">' + (type === 'promo' ? '\u{1F389}' : type === 'warning' ? '\u26A0' : '\u{2139}') + '</span>' +
        '<span>' + msg + '</span>' +
        '<button onclick="this.parentElement.remove()" style="background:none;border:none;color:#ffd700;cursor:pointer;font-size:16px;margin-left:auto;">&times;</button>';
    document.body.insertBefore(banner, document.body.firstChild);
    setTimeout(function() { if (banner.parentElement) banner.remove(); }, 30000);
}


