/* ── 363-370 — AML transaction monitoring ────────────────────── */
var _amlThresholds = { singleTx: 3000, dailyTotal: 10000, rapidDeposits: 5 };
var _amlDailyTotal = 0;
var _amlDepositCount = 0;
function _amlCheckTransaction(amount, type) {
    if (type === 'deposit') {
        _amlDailyTotal += amount;
        _amlDepositCount++;
        if (amount >= _amlThresholds.singleTx) {
            _amlFlag('Large single transaction: $' + amount.toFixed(2), 'high');
        }
        if (_amlDailyTotal >= _amlThresholds.dailyTotal) {
            _amlFlag('Daily deposit threshold exceeded: $' + _amlDailyTotal.toFixed(2), 'critical');
        }
        if (_amlDepositCount >= _amlThresholds.rapidDeposits) {
            _amlFlag('Rapid deposit pattern detected: ' + _amlDepositCount + ' deposits', 'medium');
        }
    }
}
function _amlFlag(reason, severity) {
    console.warn('[AML] Flag:', severity, reason);
    fetch('/api/admin/aml/flag', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + (typeof authToken !== 'undefined' ? authToken : '') },
        body: JSON.stringify({ reason: reason, severity: severity, timestamp: Date.now() })
    }).catch(function() {});
}


