function _setMeta(name, content) {
    var isOg = name.startsWith('og:') || name.startsWith('twitter:');
    var attr = isOg ? 'property' : 'name';
    var el = document.querySelector('meta[' + attr + '="' + name + '"]');
    if (!el) { el = document.createElement('meta'); el.setAttribute(attr, name); document.head.appendChild(el); }
    el.setAttribute('content', content);
}


/* ── 403-410 — analytics event tracking ──────────────────────── */
function _initAnalytics() {
    if (typeof gtag === 'undefined') return;
    gtag('event', 'page_view', { page_title: 'Matrix Spins Casino' });
}
function _trackEvent(category, action, label, value) {
    if (typeof gtag !== 'undefined') {
        gtag('event', action, { event_category: category, event_label: label, value: value });
    }
    var events = JSON.parse(localStorage.getItem('ms_analytics_events') || '[]');
    events.push({ cat: category, act: action, lbl: label, val: value, ts: Date.now() });
    if (events.length > 1000) events = events.slice(-1000);
    localStorage.setItem('ms_analytics_events', JSON.stringify(events));
}
function _trackDeposit(amount) { _trackEvent('monetization', 'deposit', 'usd', amount); }
