// --- Sprint 431 — Promo Scheduler ---
var _scheduledPromos = [];
function _initPromoScheduler() {
    _scheduledPromos = [
        { name: 'Happy Hour 2x', startHour: 18, endHour: 20, bonus: 2 },
        { name: 'Weekend Boost', dayOfWeek: [0, 6], bonus: 1.5 },
        { name: 'Late Night Special', startHour: 22, endHour: 2, bonus: 1.75 }
    ];
    _checkActivePromos();
}
function _checkActivePromos() {
    var now = new Date();
    var hour = now.getHours();
    var day = now.getDay();
    var activePromo = null;
    _scheduledPromos.forEach(function(p) {
        if (p.dayOfWeek && p.dayOfWeek.indexOf(day) === -1) return;
        if (p.startHour !== undefined) {
            if (p.startHour < p.endHour) {
                if (hour >= p.startHour && hour < p.endHour) activePromo = p;
            } else {
                if (hour >= p.startHour || hour < p.endHour) activePromo = p;
            }
        } else if (p.dayOfWeek) { activePromo = p; }
    });
    if (activePromo) _showPromoBanner(activePromo);
}
function _showPromoBanner(promo) {
    var el = document.getElementById('activePromoBanner');
    if (!el) {
        el = document.createElement('div');
        el.id = 'activePromoBanner';
        el.className = 'active-promo-banner';
        document.body.appendChild(el);
    }
    el.innerHTML = '<span class="promo-name">' + promo.name + '</span> <span class="promo-mult">' + promo.bonus + 'x Bonus Active!</span>';
    el.style.display = 'flex';
}


// --- Sprint 432 — Withdrawal Queue ---
var _withdrawalQueue = [];
function _initWithdrawalQueue() {
    try { var saved = localStorage.getItem('ms_withdrawals'); if (saved) _withdrawalQueue = JSON.parse(saved); } catch(e) {}
}
function _requestWithdrawal(amount, method) {
    if (typeof balance !== 'undefined' && balance < amount) { alert('Insufficient balance'); return; }
    var req = { id: Date.now(), amount: amount, method: method || 'bank', status: 'pending', created: new Date().toISOString() };
    _withdrawalQueue.push(req);
    if (typeof balance !== 'undefined') balance -= amount;
    if (typeof updateBalanceDisplay === 'function') updateBalanceDisplay();
    try { localStorage.setItem('ms_withdrawals', JSON.stringify(_withdrawalQueue)); } catch(e) {}
    _showWithdrawalConfirm(req);
}
function _showWithdrawalConfirm(req) {
    var el = document.getElementById('withdrawConfirmToast');
    if (!el) {
        el = document.createElement('div');
        el.id = 'withdrawConfirmToast';
        el.className = 'withdraw-confirm-toast';
        document.body.appendChild(el);
    }
    el.innerHTML = 'Withdrawal of $' + req.amount.toFixed(2) + ' submitted! Processing in 24-48 hrs.';
    el.style.display = 'block';
    setTimeout(function() { el.style.display = 'none'; }, 5000);
}


