// --- Sprint 450 — Play History Export ---
function _initPlayHistoryExport() {}
function _exportPlayHistory() {
    var history = [];
    try { history = JSON.parse(localStorage.getItem('ms_playHistory') || '[]'); } catch(e) {}
    if (history.length === 0) { alert('No play history available'); return; }
    var csv = 'Date,Game,Bet,Win,Net Result\n';
    history.forEach(function(h) {
        csv += h.date + ',' + h.game + ',' + h.bet + ',' + h.win + ',' + (h.win - h.bet) + '\n';
    });
    var blob = new Blob([csv], { type: 'text/csv' });
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url; a.download = 'play-history-' + new Date().toISOString().split('T')[0] + '.csv';
    a.click(); URL.revokeObjectURL(url);
}
function _recordPlayHistory(game, bet, win) {
    try {
        var history = JSON.parse(localStorage.getItem('ms_playHistory') || '[]');
        history.push({ date: new Date().toISOString(), game: game || 'unknown', bet: bet || 0, win: win || 0 });
        if (history.length > 10000) history = history.slice(-10000);
        localStorage.setItem('ms_playHistory', JSON.stringify(history));
    } catch(e) {}
}


// --- Sprint 451 — VIP Upgrade Prompts ---
var _vipPromptShown = false;
function _initVIPUpgradePrompts() { _vipPromptShown = false; }
function _checkVIPUpgrade(totalWagered) {
    if (_vipPromptShown || !totalWagered) return;
    var tiers = [
        { name: 'Silver', threshold: 500, bonus: '5% cashback' },
        { name: 'Gold', threshold: 2000, bonus: '10% cashback + priority withdrawals' },
        { name: 'Platinum', threshold: 10000, bonus: '15% cashback + personal host' },
        { name: 'Diamond', threshold: 50000, bonus: '20% cashback + exclusive events' }
    ];
    var currentTier = null;
    var nextTier = null;
    for (var i = 0; i < tiers.length; i++) {
        if (totalWagered >= tiers[i].threshold) currentTier = tiers[i];
        else { nextTier = tiers[i]; break; }
    }
    if (nextTier && totalWagered >= nextTier.threshold * 0.8) {
        _vipPromptShown = true;
        _showVIPUpgradePrompt(currentTier, nextTier, totalWagered);
    }
}
function _showVIPUpgradePrompt(current, next, wagered) {
    var el = document.getElementById('vipUpgradePrompt');
    if (!el) { el = document.createElement('div'); el.id = 'vipUpgradePrompt'; el.className = 'vip-upgrade-prompt'; document.body.appendChild(el); }
    var remaining = next.threshold - wagered;
    el.innerHTML = '<div class="vip-prompt-card"><h3>VIP Upgrade Available!</h3>' +
        '<p>You are <strong>' + remaining.toFixed(0) + '</strong> away from <span class="vip-tier-name">' + next.name + '</span> status!</p>' +
        '<p class="vip-benefit">' + next.bonus + '</p>' +
        '<button onclick="document.getElementById(&quot;vipUpgradePrompt&quot;).style.display=&quot;none&quot;" class="vip-ok">Keep Playing!</button></div>';
    el.style.display = 'flex';
    setTimeout(function() { el.style.display = 'none'; }, 10000);
}


