// --- Sprint 463 — Cache Manager ---
function _initCacheManager() {
    _cleanExpiredCache();
}
function _setCache(key, data, ttlMs) {
    try {
        var entry = { data: data, expires: Date.now() + (ttlMs || 300000) };
        localStorage.setItem('cache_' + key, JSON.stringify(entry));
    } catch(e) { _evictOldestCache(); }
}
function _getCache(key) {
    try {
        var raw = localStorage.getItem('cache_' + key);
        if (!raw) return null;
        var entry = JSON.parse(raw);
        if (Date.now() > entry.expires) { localStorage.removeItem('cache_' + key); return null; }
        return entry.data;
    } catch(e) { return null; }
}
function _cleanExpiredCache() {
    try {
        for (var i = localStorage.length - 1; i >= 0; i--) {
            var k = localStorage.key(i);
            if (k && k.startsWith('cache_')) {
                try { var e = JSON.parse(localStorage.getItem(k)); if (Date.now() > e.expires) localStorage.removeItem(k); } catch(e2) {}
            }
        }
    } catch(e) {}
}
function _evictOldestCache() {
    var oldest = null, oldestTime = Infinity;
    try {
        for (var i = 0; i < localStorage.length; i++) {
            var k = localStorage.key(i);
            if (k && k.startsWith('cache_')) {
                try { var e = JSON.parse(localStorage.getItem(k)); if (e.expires < oldestTime) { oldestTime = e.expires; oldest = k; } } catch(e2) {}
            }
        }
        if (oldest) localStorage.removeItem(oldest);
    } catch(e) {}
}


