// --- Sprint 475 — Device Fingerprinting ---
var _deviceFingerprint = '';
function _initDeviceFingerprint() {
    var canvas = document.createElement('canvas');
    var ctx = canvas.getContext('2d');
    ctx.textBaseline = 'top';
    ctx.font = '14px Arial';
    ctx.fillText('MatrixSpins', 2, 2);
    var canvasHash = canvas.toDataURL().slice(-50);
    var screenInfo = screen.width + 'x' + screen.height + 'x' + screen.colorDepth;
    var tz = Intl.DateTimeFormat().resolvedOptions().timeZone || '';
    var plugins = navigator.plugins ? navigator.plugins.length : 0;
    var raw = canvasHash + '|' + screenInfo + '|' + tz + '|' + navigator.language + '|' + plugins + '|' + navigator.hardwareConcurrency;
    _deviceFingerprint = _simpleHash(raw);
    try { localStorage.setItem('ms_deviceFP', _deviceFingerprint); } catch(e) {}
}
function _simpleHash(str) {
    var hash = 0;
    for (var i = 0; i < str.length; i++) { hash = ((hash << 5) - hash) + str.charCodeAt(i); hash |= 0; }
    return 'fp_' + Math.abs(hash).toString(36);
}


// --- Sprint 476 — Velocity Checks ---
var _velocityLog = [];
var _velocityMaxPerMinute = 60;
function _initVelocityChecks() { _velocityLog = []; }
function _checkVelocity(action) {
    var now = Date.now();
    _velocityLog.push({ action: action, time: now });
    _velocityLog = _velocityLog.filter(function(e) { return now - e.time < 60000; });
    if (_velocityLog.length > _velocityMaxPerMinute) {
        _flagSuspiciousActivity('velocity', 'Too many actions per minute: ' + _velocityLog.length);
        return false;
    }
    return true;
}


