// --- Sprint 494 — Churn Risk Scoring ---
function _initChurnRisk() {}
function _calculateChurnRisk() {
    var risk = 0;
    try {
        var lastVisit = parseInt(localStorage.getItem('ms_lastVisitV2') || Date.now().toString());
        var daysSince = (Date.now() - lastVisit) / 86400000;
        if (daysSince > 7) risk += 40;
        else if (daysSince > 3) risk += 20;
        var stats = JSON.parse(localStorage.getItem('casinoStats') || '{}');
        var netResult = (stats.totalWon || 0) - (stats.totalWagered || 0);
        if (netResult < -500) risk += 30;
        else if (netResult < -100) risk += 15;
        if ((stats.totalSpins || 0) < 20) risk += 20;
    } catch(e) {}
    return Math.min(100, risk);
}
function _openChurnDashboard() {
    var risk = _calculateChurnRisk();
    var color = risk > 60 ? '#e74c3c' : risk > 30 ? '#f39c12' : '#2ecc71';
    var label = risk > 60 ? 'HIGH RISK' : risk > 30 ? 'MEDIUM' : 'LOW';
    var el = document.getElementById('churnDashOverlay');
    if (!el) { el = document.createElement('div'); el.id = 'churnDashOverlay'; el.className = 'churn-dash-overlay'; document.body.appendChild(el); }
    el.innerHTML = '<div class="churn-card"><h3>Churn Risk Score</h3>' +
        '<div class="churn-score" style="color:' + color + '">' + risk + '/100</div>' +
        '<div class="churn-label" style="background:' + color + '">' + label + '</div>' +
        '<p>Based on login frequency, net P/L, and engagement level.</p>' +
        '<button onclick="document.getElementById(&quot;churnDashOverlay&quot;).style.display=&quot;none&quot;" class="churn-close">Close</button></div>';
    el.style.display = 'flex';
}


