// --- Sprint 496 — Player Activity Heatmap ---
function _initPlayerHeatmap() {}
function _openPlayerHeatmap() {
    var el = document.getElementById('heatmapOverlay');
    if (!el) { el = document.createElement('div'); el.id = 'heatmapOverlay'; el.className = 'heatmap-overlay'; document.body.appendChild(el); }
    var hours = [];
    for (var d = 0; d < 7; d++) {
        for (var h = 0; h < 24; h++) {
            hours.push({ day: d, hour: h, intensity: Math.random() });
        }
    }
    var days = ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'];
    var html = '<div class="hm-card"><h3>Player Activity Heatmap</h3><div class="hm-grid">';
    html += '<div class="hm-row hm-header"><span></span>';
    for (var hh = 0; hh < 24; hh += 3) html += '<span>' + hh + '</span>';
    html += '</div>';
    for (var dd = 0; dd < 7; dd++) {
        html += '<div class="hm-row"><span class="hm-day">' + days[dd] + '</span>';
        for (var hh2 = 0; hh2 < 24; hh2++) {
            var val = hours[dd * 24 + hh2].intensity;
            var opacity = (val * 0.8 + 0.1).toFixed(2);
            html += '<div class="hm-cell" style="opacity:' + opacity + '" title="' + days[dd] + ' ' + hh2 + ':00"></div>';
        }
        html += '</div>';
    }
    html += '</div><button onclick="document.getElementById(&quot;heatmapOverlay&quot;).style.display=&quot;none&quot;" class="hm-close">Close</button></div>';
    el.innerHTML = html;
    el.style.display = 'flex';
}


// --- Sprint 497 — Revenue Alerts ---
var _revenueAlertThresholds = { hourly: 100, daily: 500, drop: -20 };
function _initRevenueAlerts() {}
function _checkRevenueAlert(currentRevenue, previousRevenue) {
    if (!currentRevenue) return;
    var change = previousRevenue > 0 ? ((currentRevenue - previousRevenue) / previousRevenue) * 100 : 0;
    if (change <= _revenueAlertThresholds.drop) {
        if (typeof _addNotification === 'function') _addNotification('Revenue Alert', 'Revenue dropped ' + Math.abs(change).toFixed(1) + '% from previous period', 'warning');
    }
    if (currentRevenue >= _revenueAlertThresholds.daily) {
        if (typeof _addNotification === 'function') _addNotification('Revenue Milestone', 'Daily revenue target of $' + _revenueAlertThresholds.daily + ' reached!', 'success');
    }
}


// --- Sprint 498 — Automated Reports ---
function _initAutomatedReports() {}
function _generateDailyReport() {
    var stats = {};
    try { stats = JSON.parse(localStorage.getItem('casinoStats') || '{}'); } catch(e) {}
    var report = {
        date: new Date().toISOString().split('T')[0],
        revenue: (_totalRevenue || 0).toFixed(2),
        totalSpins: stats.totalSpins || 0,
        totalWagered: (stats.totalWagered || 0).toFixed(2),
        totalWon: (stats.totalWon || 0).toFixed(2),
        houseEdge: (((stats.totalWagered || 0) - (stats.totalWon || 0)) / Math.max(1, stats.totalWagered || 1) * 100).toFixed(2) + '%',
        churnRisk: (typeof _calculateChurnRisk === 'function') ? _calculateChurnRisk() : 'N/A'
    };
    return report;
}
function _downloadDailyReport() {
    var report = _generateDailyReport();
    var csv = Object.keys(report).join(',') + '\n' + Object.values(report).join(',');
    var blob = new Blob([csv], { type: 'text/csv' });
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url; a.download = 'daily-report-' + report.date + '.csv';
    a.click(); URL.revokeObjectURL(url);
}


