// === Sprint 523-530 Feature 1: Leaderboard Seasons ===
function _initLeaderboardSeasons() {
    if (document.getElementById('lb-season-panel')) return;
    var season = JSON.parse(localStorage.getItem('ms_lb_season') || '{"number":1,"startTs":' + Date.now() + ',"entries":[]}');
    var daysLeft = Math.max(0, 30 - Math.floor((Date.now() - season.startTs) / 86400000));
    if (daysLeft <= 0) { season = {number: season.number+1, startTs: Date.now(), entries: []}; localStorage.setItem('ms_lb_season', JSON.stringify(season)); daysLeft = 30; }
    var panel = document.createElement('div');
    panel.id = 'lb-season-panel';
    panel.className = 'lb-season-panel hidden';
    // Season leaderboard previously mixed 9 hardcoded fake players with
    // the real user's score. Dropped — show only the user's own tally
    // until a real multi-user ranking endpoint exists.
    var myScore = parseInt(localStorage.getItem('ms_total_wagered') || '0', 10) || 0;
    var rows = '<div class="lb-row lb-you"><span class="lb-rank">#1</span><span class="lb-name">You</span><span class="lb-score">$' + myScore.toLocaleString() + '</span></div>';
    panel.innerHTML = '<div class="lb-inner"><h3>Season '+season.number+' Leaderboard</h3><div class="lb-timer">'+daysLeft+' days remaining</div><div class="lb-prizes"><span>1st: $500</span><span>2nd: $250</span><span>3rd: $100</span></div>'+rows+'<p style="color:#8a8a8a;font-size:12px;margin-top:10px">Other players appear once real standings are collected.</p></div>';
    document.body.appendChild(panel);
    console.log('[Sprint 523-530] Leaderboard Seasons ready');
}

/* ---- Feature 2: Friend System ---- */
function _initFriendSystem() {
    if (document.getElementById('friends-btn')) return;
    var friends = JSON.parse(localStorage.getItem('ms_friends') || '[]');
    var btn = document.createElement('button');
    btn.id = 'friends-btn';
    btn.className = 'friends-btn';
    btn.textContent = 'Friends (' + friends.length + ')';
    btn.addEventListener('click', function() {
        var modal = document.createElement('div');
        modal.className = 'friends-modal'; modal.id = 'friends-modal';
        var list = friends.length ? friends.map(function(f) {
            return '<div class="fr-item"><span class="fr-name">'+f.name+'</span><span class="fr-status '+(f.online?'fr-online':'fr-offline')+'">'+(f.online?'Online':'Offline')+'</span><button class="fr-gift" data-name="'+f.name+'">Send Gift</button></div>';
        }).join('') : '<p class="fr-empty">No friends yet. Share your referral code to add friends!</p>';
        modal.innerHTML = '<div class="fr-inner"><h3>Friends</h3><div class="fr-add"><input type="text" id="fr-add-input" placeholder="Enter friend code"><button id="fr-add-btn" class="fr-add-submit">Add</button></div><div class="fr-list">'+list+'</div><button class="fr-close" onclick="document.getElementById(&quot;friends-modal&quot;).remove()">Close</button></div>';
        document.body.appendChild(modal);
        document.getElementById('fr-add-btn').addEventListener('click', function() {
            var code = document.getElementById('fr-add-input').value.trim();
            if (!code) return;
            friends.push({name: code, online: Math.random()>0.5, added: Date.now()});
            localStorage.setItem('ms_friends', JSON.stringify(friends));
            btn.textContent = 'Friends (' + friends.length + ')';
            modal.remove(); 
        });
    });
    document.body.appendChild(btn);
    console.log('[Sprint 523-530] Friend System ready');
}

