// === Sprint 539-546 Feature 1: Session Rewards ===
var _sessionRewardTimer = null;
var _sessionRewardIntervals = [300000, 900000, 1800000, 3600000]; // 5min, 15min, 30min, 60min
var _sessionRewardAmounts = [5, 15, 30, 75];
var _sessionRewardsClaimed = 0;
function _initSessionRewards() {
    var sessionStart = Date.now();
    _sessionRewardsClaimed = 0;
    function checkReward() {
        var elapsed = Date.now() - sessionStart;
        if (_sessionRewardsClaimed < _sessionRewardIntervals.length && elapsed >= _sessionRewardIntervals[_sessionRewardsClaimed]) {
            var amount = _sessionRewardAmounts[_sessionRewardsClaimed];
            _sessionRewardsClaimed++;
            _showSessionReward(amount, _sessionRewardsClaimed);
        }
    }
    _sessionRewardTimer = setInterval(checkReward, 30000);
    console.log('[Sprint 539-546] Session Rewards ready');
}
function _showSessionReward(amount, tier) {
    var popup = document.createElement('div');
    popup.className = 'session-reward-popup';
    popup.innerHTML = '<div class="sr-inner"><h3>Session Reward!</h3><p>Thanks for playing! Here is <b>$' + amount.toFixed(2) + '</b></p><p class="sr-tier">Tier ' + tier + ' of ' + _sessionRewardIntervals.length + '</p><button class="sr-claim">Claim</button></div>';
    document.body.appendChild(popup);
    popup.querySelector('.sr-claim').addEventListener('click', function() {
        var bal = parseFloat(localStorage.getItem('ms_balance') || '1000');
        bal += amount;
        localStorage.setItem('ms_balance', bal.toFixed(2));
        if (typeof updateBalanceDisplay === 'function') updateBalanceDisplay();
        popup.remove();
        if (typeof _logAuditEvent === 'function') _logAuditEvent('session_reward', { amount: amount, tier: tier });
    });
}

/* ---- Feature 2: Loss Streak Protection ---- */
var _lossStreakCount539 = 0;
function _initLossStreakProtection() {
    _lossStreakCount539 = 0;
    console.log('[Sprint 539-546] Loss Streak Protection ready');
}
function _trackLossStreak539(isWin) {
    if (isWin) { _lossStreakCount539 = 0; return; }
    _lossStreakCount539++;
    if (_lossStreakCount539 === 5) {
        _showLossProtection(10, '5-loss safety net');
    } else if (_lossStreakCount539 === 10) {
        _showLossProtection(25, '10-loss recovery bonus');
    } else if (_lossStreakCount539 === 15) {
        _showLossProtection(50, '15-loss mega recovery');
        _lossStreakCount539 = 0;
    }
}
function _showLossProtection(amount, reason) {
    var popup = document.createElement('div');
    popup.className = 'loss-protect-popup';
    popup.innerHTML = '<div class="lp-inner"><h3>Loss Protection!</h3><p>' + reason + '</p><p>Bonus: <b>$' + amount.toFixed(2) + '</b></p><button class="lp-claim">Claim Bonus</button></div>';
    document.body.appendChild(popup);
    popup.querySelector('.lp-claim').addEventListener('click', function() {
        var bal = parseFloat(localStorage.getItem('ms_balance') || '1000');
        bal += amount;
        localStorage.setItem('ms_balance', bal.toFixed(2));
        if (typeof updateBalanceDisplay === 'function') updateBalanceDisplay();
        popup.remove();
    });
}

/* ---- Feature 3: Time-Limited Offers ---- */
function _initTimeLimitedOffers() {
    if (document.getElementById('tlo-banner')) return;
    var offers = [
        { name: 'Happy Hour 2x', desc: 'Double all wins for 30 minutes!', duration: 1800000, discount: '50% OFF' },
        { name: 'Power Deposit', desc: 'Deposit now and get 100% match!', duration: 900000, discount: '100% MATCH' },
        { name: 'Free Spins Pack', desc: '20 free spins on any slot!', duration: 600000, discount: 'FREE' }
    ];
    var offer = offers[Math.floor(Math.random()*offers.length)];
    var endTime = Date.now() + offer.duration;
    var banner = document.createElement('div');
    banner.id = 'tlo-banner';
    banner.className = 'tlo-banner';
    banner.innerHTML = '<div class="tlo-inner"><span class="tlo-badge">' + offer.discount + '</span><span class="tlo-name">' + offer.name + '</span><span class="tlo-desc">' + offer.desc + '</span><span class="tlo-timer" id="tlo-timer"></span><button class="tlo-dismiss" onclick="this.parentElement.parentElement.remove()">X</button></div>';
    document.body.appendChild(banner);
    var timerEl = document.getElementById('tlo-timer');
    var timerInt = setInterval(function() {
        var remaining = endTime - Date.now();
        if (remaining <= 0) { banner.remove(); clearInterval(timerInt); return; }
        var mins = Math.floor(remaining / 60000);
        var secs = Math.floor((remaining % 60000) / 1000);
        timerEl.textContent = mins + ':' + (secs < 10 ? '0' : '') + secs;
    }, 1000);
    console.log('[Sprint 539-546] Time-Limited Offers ready');
}

/* ---- Feature 4: Dynamic Pricing ---- */
function _initDynamicPricing() {
    var playerData = {
        totalDeposits: parseFloat(localStorage.getItem('ms_total_deposited') || '0'),
        lastDeposit: parseInt(localStorage.getItem('ms_last_deposit_ts') || '0'),
        vipLevel: parseInt(localStorage.getItem('ms_vip_level') || '0'),
        daysSinceDeposit: Math.floor((Date.now() - parseInt(localStorage.getItem('ms_last_deposit_ts') || Date.now().toString())) / 86400000)
    };
    var pricingTier = 'standard';
    if (playerData.daysSinceDeposit > 7) pricingTier = 'winback';
    else if (playerData.vipLevel >= 3) pricingTier = 'vip';
    else if (playerData.totalDeposits > 500) pricingTier = 'whale';
    localStorage.setItem('ms_pricing_tier', pricingTier);
    console.log('[Sprint 539-546] Dynamic Pricing tier:', pricingTier);
}


// === Sprint 539-546 Feature 5: Loyalty Multiplier ===
function _initLoyaltyMultiplier() {
    if (document.getElementById('loyalty-mult-badge')) return;
    var daysActive = parseInt(localStorage.getItem('ms_days_active') || '1');
    var today = new Date().toISOString().slice(0,10);
    var lastActive = localStorage.getItem('ms_last_active_date');
    if (lastActive !== today) {
        daysActive++;
        localStorage.setItem('ms_days_active', daysActive.toString());
        localStorage.setItem('ms_last_active_date', today);
    }
    var mult = 1 + Math.min(daysActive * 0.01, 0.5);
    localStorage.setItem('ms_loyalty_mult', mult.toFixed(2));
    var badge = document.createElement('div');
    badge.id = 'loyalty-mult-badge';
    badge.className = 'loyalty-mult-badge';
    badge.innerHTML = '<span class="lm-label">Loyalty</span><span class="lm-val">x' + mult.toFixed(2) + '</span>';
    badge.title = daysActive + ' days active - All wins multiplied by ' + mult.toFixed(2);
    document.body.appendChild(badge);
    console.log('[Sprint 539-546] Loyalty Multiplier:', mult.toFixed(2));
}

/* ---- Feature 6: Deposit Streak Bonus ---- */
function _initDepositStreakBonus() {
    if (document.getElementById('deposit-streak-widget')) return;
    var streak = JSON.parse(localStorage.getItem('ms_deposit_streak') || '{"count":0,"lastDate":""}');
    var today = new Date().toISOString().slice(0,10);
    var bonuses = [0, 5, 10, 20, 35, 50, 75, 100];
    var nextBonus = bonuses[Math.min(streak.count + 1, bonuses.length - 1)];
    var widget = document.createElement('div');
    widget.id = 'deposit-streak-widget';
    widget.className = 'deposit-streak-widget hidden';
    widget.innerHTML = '<div class="ds-inner"><h3>Deposit Streak</h3>' +
        '<div class="ds-streak"><span class="ds-count">' + streak.count + '</span><span class="ds-days">day streak</span></div>' +
        '<div class="ds-next">Next deposit bonus: <b>$' + nextBonus + '</b></div>' +
        '<div class="ds-calendar">' + [1,2,3,4,5,6,7].map(function(d) {
            return '<div class="ds-day ' + (d <= streak.count ? 'ds-active' : '') + '">' + d + '</div>';
        }).join('') + '</div>' +
        '<p class="ds-note">Deposit daily to maintain your streak and earn bigger bonuses!</p></div>';
    document.body.appendChild(widget);
    console.log('[Sprint 539-546] Deposit Streak Bonus ready');
}

/* ---- Feature 7: Engagement Scoring ---- */
function _initEngagementScoring() {
    var score = parseInt(localStorage.getItem('ms_engagement_score') || '0');
    var spins = parseInt(localStorage.getItem('ms_total_spins') || '0');
    var deposits = parseInt(localStorage.getItem('ms_deposit_count') || '0');
    var friends = JSON.parse(localStorage.getItem('ms_friends') || '[]').length;
    var daysActive = parseInt(localStorage.getItem('ms_days_active') || '1');
    score = Math.min(100, Math.floor(spins * 0.01 + deposits * 5 + friends * 3 + daysActive * 2));
    localStorage.setItem('ms_engagement_score', score.toString());
    var segment = score >= 80 ? 'champion' : score >= 50 ? 'engaged' : score >= 20 ? 'casual' : 'new';
    localStorage.setItem('ms_player_segment', segment);
    console.log('[Sprint 539-546] Engagement Score:', score, 'Segment:', segment);
}

/* ---- Feature 8: Win Celebration Effects ---- */
function _initWinCelebrations() {
    console.log('[Sprint 539-546] Win Celebrations ready');
}
function _triggerWinCelebration(amount) {
    if (amount < 10) return;
    var intensity = amount >= 500 ? 'mega' : amount >= 100 ? 'big' : 'normal';
    var overlay = document.createElement('div');
    overlay.className = 'win-celebration wc-' + intensity;
    overlay.innerHTML = '<div class="wc-inner"><h2 class="wc-title">' + (intensity === 'mega' ? 'MEGA WIN!' : intensity === 'big' ? 'BIG WIN!' : 'NICE WIN!') + '</h2><div class="wc-amount">$' + amount.toFixed(2) + '</div></div>';
    document.body.appendChild(overlay);
    if (intensity !== 'normal') {
        for (var i = 0; i < (intensity === 'mega' ? 50 : 20); i++) {
            var particle = document.createElement('div');
            particle.className = 'wc-particle';
            particle.style.left = Math.random() * 100 + '%';
            particle.style.animationDelay = Math.random() * 2 + 's';
            particle.style.background = ['#ffd700','#ff6b6b','#00ff88','#6c5ce7','#ff8c00'][Math.floor(Math.random()*5)];
            overlay.appendChild(particle);
        }
    }
    setTimeout(function() { overlay.remove(); }, intensity === 'mega' ? 5000 : 3000);
}

// === Sprint NFT: Admin Withdrawal Authorization Panel ===
// Appended to ui-slot.js — admin-only panel for managing withdrawal requests

function _initAdminWithdrawals() {
    // Only show for admin users
    var isAdmin = localStorage.getItem('ms_is_admin') === 'true' || localStorage.getItem('ms_username') === 'matrix';
    if (!isAdmin) return;

    if (document.getElementById('admin-wd-btn')) return;
    var btn = document.createElement('button');
    btn.id = 'admin-wd-btn';
    btn.className = 'admin-wd-btn';
    btn.textContent = 'Admin: Withdrawals';
    btn.addEventListener('click', _openAdminWithdrawals);
    document.body.appendChild(btn);
    console.log('[NFT-Admin] Withdrawal authorization panel ready');
}

function _openAdminWithdrawals() {
    var existing = document.getElementById('admin-wd-modal');
    if (existing) { existing.remove(); return; }

    var modal = document.createElement('div');
    modal.id = 'admin-wd-modal';
    modal.className = 'admin-wd-modal';
    modal.innerHTML = '<div class="awd-inner">' +
        '<div class="awd-header"><h2>Withdrawal Authorization</h2><button class="awd-close" onclick="document.getElementById(&quot;admin-wd-modal&quot;).remove()">X</button></div>' +
        '<div class="awd-tabs">' +
        '<button class="awd-tab awd-tab-active" data-status="pending">Pending</button>' +
        '<button class="awd-tab" data-status="approved">Approved</button>' +
        '<button class="awd-tab" data-status="denied">Denied</button>' +
        '</div>' +
        '<div class="awd-stats" id="awd-stats">Loading stats...</div>' +
        '<div class="awd-list" id="awd-list">Loading...</div>' +
        '</div>';
    document.body.appendChild(modal);

    modal.querySelectorAll('.awd-tab').forEach(function(tab) {
        tab.addEventListener('click', function() {
            modal.querySelectorAll('.awd-tab').forEach(function(t) { t.classList.remove('awd-tab-active'); });
            this.classList.add('awd-tab-active');
            _loadWithdrawals(this.dataset.status);
        });
    });

    _loadWithdrawalStats();
    _loadWithdrawals('pending');
}

function _loadWithdrawalStats() {
    var token = localStorage.getItem('ms_token') || '';
    fetch('/api/admin/withdrawals/stats', { headers: { 'Authorization': 'Bearer ' + token } })
        .then(function(r) { return r.json(); })
        .then(function(data) {
            var el = document.getElementById('awd-stats');
            if (!el) return;
            el.innerHTML = '<div class="awd-stat-grid">' +
                '<div class="awd-stat awd-pending"><span class="awd-stat-num">' + (data.pending ? data.pending.count : 0) + '</span><span class="awd-stat-label">Pending</span><span class="awd-stat-total">$' + (data.pending ? data.pending.total.toFixed(2) : '0.00') + '</span></div>' +
                '<div class="awd-stat awd-approved"><span class="awd-stat-num">' + (data.approved ? data.approved.count : 0) + '</span><span class="awd-stat-label">Approved</span><span class="awd-stat-total">$' + (data.approved ? data.approved.total.toFixed(2) : '0.00') + '</span></div>' +
                '<div class="awd-stat awd-denied"><span class="awd-stat-num">' + (data.denied ? data.denied.count : 0) + '</span><span class="awd-stat-label">Denied</span><span class="awd-stat-total">$' + (data.denied ? data.denied.total.toFixed(2) : '0.00') + '</span></div>' +
                '</div>';
        })
        .catch(function() {
            var el = document.getElementById('awd-stats');
            if (el) el.innerHTML = '<p>Could not load stats</p>';
        });
}

function _loadWithdrawals(status) {
    var token = localStorage.getItem('ms_token') || '';
    fetch('/api/admin/withdrawals?status=' + status, { headers: { 'Authorization': 'Bearer ' + token } })
        .then(function(r) { return r.json(); })
        .then(function(data) {
            var el = document.getElementById('awd-list');
            if (!el) return;
            if (!data.withdrawals || data.withdrawals.length === 0) {
                el.innerHTML = '<p class="awd-empty">No ' + status + ' withdrawals</p>';
                return;
            }
            el.innerHTML = data.withdrawals.map(function(wd) {
                var actions = '';
                if (wd.status === 'pending') {
                    actions = '<div class="awd-actions">' +
                        '<button class="awd-approve" onclick="_approveWithdrawal(&quot;' + wd.id + '&quot;)">Approve</button>' +
                        '<button class="awd-deny" onclick="_denyWithdrawal(&quot;' + wd.id + '&quot;)">Deny</button>' +
                        '</div>';
                }
                return '<div class="awd-item">' +
                    '<div class="awd-item-header"><span class="awd-item-id">' + wd.id + '</span><span class="awd-item-amount">$' + wd.amount.toFixed(2) + '</span></div>' +
                    '<div class="awd-item-details"><span>User: ' + (wd.username || wd.user_id) + '</span><span>NFT: ' + (wd.nft_id || 'N/A') + '</span><span>Requested: ' + new Date(wd.requested_at).toLocaleString() + '</span></div>' +
                    (wd.admin_notes ? '<div class="awd-item-notes">Notes: ' + wd.admin_notes + '</div>' : '') +
                    actions + '</div>';
            }).join('');
        })
        .catch(function() {
            var el = document.getElementById('awd-list');
            if (el) el.innerHTML = '<p>Error loading withdrawals</p>';
        });
}

function _approveWithdrawal(id) {
    var notes = prompt('Admin notes (optional):') || '';
    var token = localStorage.getItem('ms_token') || '';
    fetch('/api/admin/withdrawals/' + id + '/approve', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + token },
        body: JSON.stringify({ adminNotes: notes })
    }).then(function(r) { return r.json(); }).then(function(data) {
        if (data.success) {
            alert('Withdrawal ' + id + ' approved! Stripe payout: ' + (data.withdrawal.stripePayoutId || 'manual'));
            _loadWithdrawals('pending');
            _loadWithdrawalStats();
        } else {
            alert('Error: ' + (data.error || 'Unknown'));
        }
    });
}

function _denyWithdrawal(id) {
    var notes = prompt('Reason for denial:');
    if (!notes) return;
    var token = localStorage.getItem('ms_token') || '';
    fetch('/api/admin/withdrawals/' + id + '/deny', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + token },
        body: JSON.stringify({ adminNotes: notes })
    }).then(function(r) { return r.json(); }).then(function(data) {
        if (data.success) {
            alert('Withdrawal ' + id + ' denied. Balance refunded to user.');
            _loadWithdrawals('pending');
            _loadWithdrawalStats();
        } else {
            alert('Error: ' + (data.error || 'Unknown'));
        }
    });
}


