/* ---- Feature 4: Rate Limit Status ---- */
function _initRateLimitStatus() {
    if (document.getElementById('ratelimit-indicator')) return;
    var indicator = document.createElement('div');
    indicator.id = 'ratelimit-indicator';
    indicator.className = 'ratelimit-indicator hidden';
    indicator.innerHTML = '<span>Rate limited - please wait</span>';
    document.body.appendChild(indicator);
    var origFetch = window.fetch;
    window.fetch = function() {
        return origFetch.apply(this, arguments).then(function(response) {
            if (response.status === 429) {
                indicator.classList.remove('hidden');
                setTimeout(function() { indicator.classList.add('hidden'); }, 5000);
            }
            return response;
        });
    };
    console.log('[Sprint 547-554] Rate Limit Status ready');
}


// === Sprint 547-554 Feature 5: Client Error Tracking ===
var _errorLog547 = [];
function _initErrorTracking() {
    window.addEventListener('error', function(e) {
        var entry = { msg: e.message, file: e.filename, line: e.lineno, col: e.colno, ts: Date.now() };
        _errorLog547.push(entry);
        if (_errorLog547.length > 100) _errorLog547 = _errorLog547.slice(-50);
        try { localStorage.setItem('ms_error_log', JSON.stringify(_errorLog547)); } catch(ex) {}
        try {
            fetch('/api/admin/analytics/client-error', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(entry)
            }).catch(function() {});
        } catch(ex) {}
    });
    window.addEventListener('unhandledrejection', function(e) {
        var entry = { msg: 'Unhandled Promise: ' + (e.reason ? e.reason.message || String(e.reason) : 'unknown'), ts: Date.now() };
        _errorLog547.push(entry);
        if (_errorLog547.length > 100) _errorLog547 = _errorLog547.slice(-50);
    });
    console.log('[Sprint 547-554] Error Tracking ready');
}

/* ---- Feature 6: Uptime Monitor Widget ---- */
function _initUptimeMonitor() {
    if (document.getElementById('uptime-widget')) return;
    var widget = document.createElement('div');
    widget.id = 'uptime-widget';
    widget.className = 'uptime-widget';
    var startTime = Date.now();
    widget.innerHTML = '<span class="ut-dot"></span><span class="ut-label">Uptime</span><span class="ut-val" id="ut-val">checking...</span>';
    document.body.appendChild(widget);
    function checkUptime() {
        fetch('/api/health').then(function(r) {
            if (r.ok) {
                var uptime = Math.floor((Date.now() - startTime) / 1000);
                var hrs = Math.floor(uptime / 3600);
                var mins = Math.floor((uptime % 3600) / 60);
                document.getElementById('ut-val').textContent = (hrs > 0 ? hrs + 'h ' : '') + mins + 'm';
                widget.classList.remove('ut-down');
                widget.classList.add('ut-up');
            } else {
                document.getElementById('ut-val').textContent = 'degraded';
                widget.classList.add('ut-down');
            }
        }).catch(function() {
            document.getElementById('ut-val').textContent = 'offline';
            widget.classList.add('ut-down');
        });
    }
    checkUptime();
    setInterval(checkUptime, 60000);
    console.log('[Sprint 547-554] Uptime Monitor ready');
}

