// === Sprint 555-562 Feature 1: XP Leveling System ===
var _xpState = { xp: 0, level: 1, xpToNext: 100 };
function _loadXP() {
    var saved = JSON.parse(localStorage.getItem('ms_xp_state') || 'null');
    if (saved) _xpState = saved;
}
function _saveXP() { localStorage.setItem('ms_xp_state', JSON.stringify(_xpState)); }
function _addXP(amount) {
    _xpState.xp += amount;
    while (_xpState.xp >= _xpState.xpToNext) {
        _xpState.xp -= _xpState.xpToNext;
        _xpState.level++;
        _xpState.xpToNext = Math.floor(100 * Math.pow(1.15, _xpState.level - 1));
        _showLevelUp(_xpState.level);
    }
    _saveXP();
    _updateXPBar();
}
function _showLevelUp(level) {
    var popup = document.createElement('div');
    popup.className = 'levelup-popup';
    popup.innerHTML = '<h3>LEVEL UP!</h3><p>Level ' + level + '</p>';
    document.body.appendChild(popup);
    setTimeout(function() { popup.remove(); }, 3000);
    var bal = parseFloat(localStorage.getItem('ms_balance') || '1000');
    bal += level * 2;
    localStorage.setItem('ms_balance', bal.toFixed(2));
    if (typeof updateBalanceDisplay === 'function') updateBalanceDisplay();
}
function _updateXPBar() {
    var bar = document.getElementById('xp-bar-fill');
    var txt = document.getElementById('xp-level-txt');
    if (bar) bar.style.width = Math.floor(_xpState.xp / _xpState.xpToNext * 100) + '%';
    if (txt) txt.textContent = 'Lvl ' + _xpState.level;
}
function _initXPLeveling() {
    _loadXP();
    if (document.getElementById('xp-bar-widget')) return;
    var widget = document.createElement('div');
    widget.id = 'xp-bar-widget';
    widget.className = 'xp-bar-widget';
    widget.innerHTML = '<span class="xp-lvl" id="xp-level-txt">Lvl ' + _xpState.level + '</span><div class="xp-bar"><div class="xp-bar-fill" id="xp-bar-fill" style="width:' + Math.floor(_xpState.xp / _xpState.xpToNext * 100) + '%"></div></div><span class="xp-num">' + _xpState.xp + '/' + _xpState.xpToNext + '</span>';
    document.body.appendChild(widget);
    console.log('[Sprint 555-562] XP Leveling ready');
}

/* ---- Feature 2: Prestige Ranks ---- */
function _initPrestigeRanks() {
    if (document.getElementById('prestige-badge')) return;
    var level = _xpState ? _xpState.level : 1;
    var ranks = [
        { min: 1, name: 'Novice', icon: String.fromCodePoint(0x1F530), color: '#aaa' },
        { min: 10, name: 'Apprentice', icon: String.fromCodePoint(0x1F535), color: '#4ecdc4' },
        { min: 25, name: 'Adept', icon: String.fromCodePoint(0x1F7E2), color: '#00ff88' },
        { min: 50, name: 'Expert', icon: String.fromCodePoint(0x1F7E1), color: '#ffd700' },
        { min: 75, name: 'Master', icon: String.fromCodePoint(0x1F7E0), color: '#ff8c00' },
        { min: 100, name: 'Legend', icon: String.fromCodePoint(0x1F534), color: '#ff4444' },
        { min: 150, name: 'Mythic', icon: String.fromCodePoint(0x1F7E3), color: '#a29bfe' }
    ];
    var current = ranks[0];
    for (var i = ranks.length - 1; i >= 0; i--) { if (level >= ranks[i].min) { current = ranks[i]; break; } }
    var badge = document.createElement('div');
    badge.id = 'prestige-badge';
    badge.className = 'prestige-badge';
    badge.style.borderColor = current.color;
    badge.innerHTML = '<span class="pr-icon">' + current.icon + '</span><span class="pr-name" style="color:' + current.color + '">' + current.name + '</span>';
    document.body.appendChild(badge);
    console.log('[Sprint 555-562] Prestige Ranks ready');
}

