var _tournaments555 = { active: null, entries: [], endTime: 0 };
function _initTournaments555() {
    var saved = JSON.parse(localStorage.getItem('ms_tournaments555') || 'null');
    if (saved && saved.endTime > Date.now()) {
        _tournaments555 = saved;
    } else {
        _tournaments555 = {
            active: { name: 'Daily Showdown', buyIn: 0, prize: 500, maxPlayers: 50 },
            entries: _generateTournamentEntries555(),
            endTime: Date.now() + 86400000
        };
        localStorage.setItem('ms_tournaments555', JSON.stringify(_tournaments555));
    }
    console.log('[Sprint 555-562] Tournaments v3 ready');
}
function _generateTournamentEntries555() {
    var names = ['AceHigh','SlotKing','LuckyJ','SpinPro','DiamondD','GoldRush','JackpotJen','ReelDeal','WildCard','BigWinner'];
    var entries = [];
    for (var i = 0; i < names.length; i++) {
        entries.push({ name: names[i], score: Math.floor(Math.random() * 5000) });
    }
    entries.sort(function(a, b) { return b.score - a.score; });
    return entries;
}
function _addTournamentScore555(points) {
    if (!_tournaments555.active) return;
    var me = localStorage.getItem('ms_username') || 'You';
    var found = false;
    for (var i = 0; i < _tournaments555.entries.length; i++) {
        if (_tournaments555.entries[i].name === me) {
            _tournaments555.entries[i].score += points;
            found = true;
            break;
        }
    }
    if (!found) _tournaments555.entries.push({ name: me, score: points });
    _tournaments555.entries.sort(function(a, b) { return b.score - a.score; });
    localStorage.setItem('ms_tournaments555', JSON.stringify(_tournaments555));
}
function _showTournamentLeaderboard555() {
    if (document.getElementById('tourney-lb-555')) document.getElementById('tourney-lb-555').remove();
    var ol = document.createElement('div');
    ol.id = 'tourney-lb-555';
    ol.className = 'tourney-overlay555';
    var html = '<div class="tourney-inner555"><h3>Daily Showdown</h3><div class="tourney-timer555">Ends: ' + new Date(_tournaments555.endTime).toLocaleTimeString() + '</div><ol class="tourney-list555">';
    var entries = _tournaments555.entries.slice(0, 20);
    for (var i = 0; i < entries.length; i++) {
        html += '<li class="' + (i < 3 ? 'tourney-top555' : '') + '"><span>' + entries[i].name + '</span><span>' + entries[i].score.toLocaleString() + ' pts</span></li>';
    }
    html += '</ol><button class="tourney-close555" onclick="document.getElementById(&quot;tourney-lb-555&quot;).remove()">Close</button></div>';
    ol.innerHTML = html;
    document.body.appendChild(ol);
}


