function _getSmartBetSuggestion() {
    var balance = parseFloat(localStorage.getItem('ms_balance') || '1000');
    var totalSpins = parseInt(localStorage.getItem('ms_total_spins') || '0');
    var suggestion;
    if (balance < 50) {
        suggestion = { bet: 0.5, reason: 'Conservative - protect your balance' };
    } else if (balance < 200) {
        suggestion = { bet: 2, reason: 'Moderate - steady play' };
    } else if (balance < 1000) {
        suggestion = { bet: 5, reason: 'Standard - good balance for this bet' };
    } else {
        suggestion = { bet: 10, reason: 'Aggressive - high balance detected' };
    }
    if (totalSpins > 0 && totalSpins % 50 === 0) {
        suggestion.bet = Math.max(0.5, suggestion.bet * 0.5);
        suggestion.reason = 'Cool-down period - reduce bet after 50 spins';
    }
    return suggestion;
}


