/* ---- Feature 6: Player Retention Score ---- */
var _retentionScore563 = { score: 50, factors: {} };
function _initRetentionScore() {
    var saved = JSON.parse(localStorage.getItem('ms_retention563') || 'null');
    if (saved) _retentionScore563 = saved;
    _calculateRetentionScore563();
    console.log('[Sprint 563-570] Retention Score:', _retentionScore563.score);
}
function _calculateRetentionScore563() {
    var score = 50;
    var totalSpins = parseInt(localStorage.getItem('ms_total_spins') || '0');
    var totalDeposits = parseInt(localStorage.getItem('ms_total_deposits') || '0');
    var daysActive = parseInt(localStorage.getItem('ms_days_active') || '1');
    var lastVisit = parseInt(localStorage.getItem('ms_last_visit') || '0');
    var hoursSince = lastVisit > 0 ? (Date.now() - lastVisit) / 3600000 : 0;
    if (totalSpins > 500) score += 15;
    else if (totalSpins > 100) score += 10;
    else if (totalSpins > 20) score += 5;
    if (totalDeposits > 5) score += 15;
    else if (totalDeposits > 1) score += 10;
    if (daysActive > 30) score += 10;
    else if (daysActive > 7) score += 5;
    if (hoursSince < 24) score += 10;
    else if (hoursSince > 168) score -= 20;
    _retentionScore563.score = Math.max(0, Math.min(100, score));
    localStorage.setItem('ms_retention563', JSON.stringify(_retentionScore563));
}

