/* ===== Sprint 579-586: Security Hardening & Compliance ===== */

/* ---- Feature 1: Session Timeout Manager ---- */
var _sessionTimeout579 = { lastActivity: Date.now(), timeoutMs: 30 * 60 * 1000, warningMs: 25 * 60 * 1000 };
function _initSessionTimeout() {
    ['click','keydown','touchstart','mousemove'].forEach(function(evt) {
        document.addEventListener(evt, function() { _sessionTimeout579.lastActivity = Date.now(); }, { passive: true });
    });
    setInterval(function() {
        var idle = Date.now() - _sessionTimeout579.lastActivity;
        if (idle >= _sessionTimeout579.timeoutMs) {
            _logoutSession579('Session timed out due to inactivity');
        } else if (idle >= _sessionTimeout579.warningMs && !document.getElementById('session-warn-579')) {
            var warn = document.createElement('div');
            warn.id = 'session-warn-579';
            warn.className = 'session-warn579';
            warn.innerHTML = '<div class="sw-inner579"><p>Your session will expire in 5 minutes due to inactivity.</p><button onclick="document.getElementById(&quot;session-warn-579&quot;).remove()">Stay Active</button></div>';
            document.body.appendChild(warn);
        }
    }, 30000);
    console.log('[Sprint 579-586] Session Timeout ready');
}
function _logoutSession579(reason) {
    console.log('[Security] Logout:', reason);
    localStorage.removeItem('ms_token');
    localStorage.removeItem('ms_admin_mode');
    if (typeof _showNotification571 === 'function') _showNotification571(reason, 'warning', 5000);
    setTimeout(function() { window.location.reload(); }, 3000);
}

/* ---- Feature 2: Input Sanitization ---- */
function _initInputSanitization() {
    window._sanitizeInput = function(str) {
        if (typeof str !== 'string') return '';
        return str.replace(/[<>&"']/g, function(c) {
            return { '<': '&lt;', '>': '&gt;', '&': '&amp;', '"': '&quot;', "'": '&#39;' }[c] || c;
        });
    };
    window._sanitizeNumber = function(val, min, max) {
        var n = parseFloat(val);
        if (isNaN(n)) return min || 0;
        if (typeof min === 'number' && n < min) return min;
        if (typeof max === 'number' && n > max) return max;
        return n;
    };
    console.log('[Sprint 579-586] Input Sanitization ready');
}

/* ---- Feature 3: CSP Violation Reporter ---- */
function _initCSPReporter() {
    document.addEventListener('securitypolicyviolation', function(e) {
        console.warn('[CSP Violation]', {
            directive: e.violatedDirective,
            blocked: e.blockedURI,
            source: e.sourceFile + ':' + e.lineNumber
        });
        if (typeof _showNotification571 === 'function') {
            _showNotification571('Security policy violation detected', 'error', 3000);
        }
    });
    console.log('[Sprint 579-586] CSP Reporter ready');
}

/* ---- Feature 4: Anti-Tamper Detection ---- */
function _initAntiTamper() {
    var _origBalance = localStorage.getItem('ms_balance');
    var _balanceHash = _simpleHash579(_origBalance || '1000');
    localStorage.setItem('ms_balance_hash', _balanceHash);
    setInterval(function() {
        var current = localStorage.getItem('ms_balance');
        var storedHash = localStorage.getItem('ms_balance_hash');
        var expectedHash = _simpleHash579(current || '1000');
        if (storedHash && storedHash !== expectedHash) {
            console.error('[SECURITY] Balance tamper detected!');
            if (typeof _showNotification571 === 'function') {
                _showNotification571('Balance integrity check failed. Your session may be compromised.', 'error', 8000);
            }
            localStorage.setItem('ms_balance_hash', expectedHash);
        }
    }, 5000);
    console.log('[Sprint 579-586] Anti-Tamper Detection ready');
}
function _simpleHash579(str) {
    var hash = 0;
    for (var i = 0; i < str.length; i++) {
        var chr = str.charCodeAt(i);
        hash = ((hash << 5) - hash) + chr;
        hash |= 0;
    }
    return hash.toString(36);
}
function _updateBalanceHash579() {
    var bal = localStorage.getItem('ms_balance') || '1000';
    localStorage.setItem('ms_balance_hash', _simpleHash579(bal));
}


/* ---- Feature 5: Responsible Gaming Controls ---- */
