    widget.innerHTML = '<div class="dp-inner">' +
        '<span class="dp-icon">💳</span>' +
        '<span class="dp-text">Top up $' + suggested + ' for ~' + Math.floor(suggested / _dynamicPricing635.avgBet) + ' more spins!</span>' +
        '<button class="dp-btn" onclick="_handleQuickDeposit(' + suggested + ')">Deposit</button>' +
        '<button class="dp-close" onclick="this.parentElement.parentElement.style.display=\x27none\x27">✕</button></div>';
