function _playSound644(type) {
    if (_soundMgr644.muted || !_soundMgr644.enabled) return;
    try {
        var ctx = new (window.AudioContext || window.webkitAudioContext)();
        var osc = ctx.createOscillator();
        var gain = ctx.createGain();
        osc.connect(gain);
        gain.connect(ctx.destination);
        gain.gain.value = _soundMgr644.volume * 0.3;
        var freqs = { spin: 440, win: 880, bigwin: 1200, click: 600, loss: 220 };
        osc.frequency.value = freqs[type] || 440;
        osc.type = type === 'win' || type === 'bigwin' ? 'sine' : 'square';
        osc.start();
        gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.3);
        osc.stop(ctx.currentTime + 0.3);
    } catch(e) {}
}


