// === Feature 6: Responsible Gaming v2 (656) ===
var _respGaming656 = { dailyLimit: 0, dailySpent: 0, cooldownActive: false, selfExcluded: false };
function _initResponsibleGaming656() {
    var saved = JSON.parse(localStorage.getItem('ms_respgaming') || 'null');
    if (saved) _respGaming656 = Object.assign(_respGaming656, saved);
    if (_respGaming656.selfExcluded) {
        var until = _respGaming656.excludeUntil || 0;
        if (Date.now() < until) {
            _showSelfExcludeScreen(until);
            return;
        } else {
            _respGaming656.selfExcluded = false;
        }
    }
    var today = new Date().toDateString();
    if (saved && saved.lastResetDay !== today) {
        _respGaming656.dailySpent = 0;
        _respGaming656.lastResetDay = today;
        _saveRespGaming656();
    }
    console.log('[Sprint 651-658] Responsible Gaming v2 ready');
}
function _checkDailyLimit656(betAmount) {
    if (_respGaming656.dailyLimit > 0 && (_respGaming656.dailySpent + betAmount) > _respGaming656.dailyLimit) {
        if (typeof _showNotification571 === 'function') _showNotification571('Daily limit reached ($' + _respGaming656.dailyLimit + '). Take a break!', 'warning');
        return false;
    }
    _respGaming656.dailySpent += betAmount;
    _saveRespGaming656();
    return true;
}
function _saveRespGaming656() {
    _respGaming656.lastResetDay = new Date().toDateString();
    localStorage.setItem('ms_respgaming', JSON.stringify(_respGaming656));
}
function _showSelfExcludeScreen(until) {
    var overlay = document.createElement('div');
    overlay.className = 'self-exclude-overlay';
    overlay.innerHTML = '<div class="se-modal"><h2>Self-Exclusion Active</h2>' +
        '<p>You have chosen to self-exclude until ' + new Date(until).toLocaleDateString() + '.</p>' +
        '<p>If you need support, please contact a gambling helpline.</p></div>';
    document.body.appendChild(overlay);
}

// === Feature 7: Security Headers Check (657) ===
function _initSecurityHeaders657() {
    var meta = document.querySelector('meta[http-equiv="X-Frame-Options"]');
    if (!meta) {
        meta = document.createElement('meta');
        meta.setAttribute('http-equiv', 'X-Frame-Options');
        meta.setAttribute('content', 'DENY');
        document.head.appendChild(meta);
    }
    var referrer = document.querySelector('meta[name="referrer"]');
    if (!referrer) {
        referrer = document.createElement('meta');
        referrer.setAttribute('name', 'referrer');
        referrer.setAttribute('content', 'strict-origin-when-cross-origin');
        document.head.appendChild(referrer);
    }
    if (window.top !== window.self) {
        document.body.innerHTML = '<h1 style="color:red;text-align:center;margin-top:100px">This site cannot be displayed in a frame.</h1>';
    }
    console.log('[Sprint 651-658] Security Headers ready');
}

// === Feature 8: Audit Logger (658) ===
var _auditLog658 = [];
function _initAuditLogger658() {
    _auditLog658 = JSON.parse(localStorage.getItem('ms_audit') || '[]').slice(0, 500);
    _logAudit658('session_start', { ts: Date.now() });
    console.log('[Sprint 651-658] Audit Logger ready (' + _auditLog658.length + ' events)');
}
function _logAudit658(event, data) {
    _auditLog658.push({ event: event, data: data || {}, ts: Date.now() });
    if (_auditLog658.length > 500) _auditLog658.shift();
    localStorage.setItem('ms_audit', JSON.stringify(_auditLog658));
}
window._logAudit658 = _logAudit658;
